1493→        {
1494→            try
1495→            {
1496→                var sp = sender as SerialPort;
1497→                if (sp == null || !sp.IsOpen) return;
1498→
1499→                string data = sp.ReadExisting().Trim();
1500→                if (string.IsNullOrEmpty(data)) return;
1501→
1502→                // UI 스레드에서 처리
1503→                this.BeginInvoke(new Action(() =>
1504→                {
1505→                    Logger.Log($"[{sp.PortName}] Scan: {data}");
1506→                    ProcessScannerData(sp.PortName, data);
1507→                }));
1508→            }
1509→            catch (Exception ex)
1510→            {
1511→                System.Diagnostics.Debug.WriteLine($"Scanner_DataReceived error: {ex.Message}");
1512→            }
1513→        }
