1780→        public static bool CheckIoMatch(string ioOption)
1781→        {
1782→            if (string.IsNullOrWhiteSpace(ioOption))
1783→                return false;
1784→
1785→            string[] parts = ioOption.Split('/');
1786→            foreach (string part in parts)
1787→            {
1788→                if (int.TryParse(part, out int index))
1789→                {
1790→                    if (index < 0 || index >= IO.IN.Length)
1791→                        return false;
1792→
1793→                    if (!IO.IN[index])
1794→                        return false; // 조건 안 맞으면 바로 false
1795→                }
1796→                else
1797→                {
1798→                    return false; // 잘못된 문자열
1799→                }
1800→            }
1801→
1802→            return true;
1803→        }
