2094→        private void button15_Click(object sender, EventArgs e)
2095→        {
2096→            // 자동 포트 탐색 시작
2097→            button15.Enabled = false;
2098→            Logger.Log(LanguageManager.Get("port_scan_start"));
2099→
2100→            Task.Run(() =>
2101→            {
2102→                try
2103→                {
2104→                    // 기존 포트 닫기
2105→                    if (SerialAduino.IsOpen)
2106→                    {
2107→                        SerialAduino.Close();
2108→                        Thread.Sleep(500);
2109→                    }
2110→
2111→                    string foundPort = null;
2112→                    string foundVersion = null;
2113→
2114→                    // COM 포트 목록 가져오기
2115→                    string[] ports = SerialPort.GetPortNames();
2116→                    Array.Sort(ports);  // COM1, COM2, ... 순서대로 정렬
2117→
2118→                    foreach (string port in ports)
2119→                    {
2120→                        this.Invoke(new MethodInvoker(() =>
2121→                        {
2122→                            Logger.Log(LanguageManager.Get("port_checking", port));
2123→                        }));
2124→
2125→                        try
2126→                        {
2127→                            // 포트 열기 (Arduino는 115200 baud)
2128→                            SerialPort testPort = new SerialPort(port, 115200);
2129→                            testPort.Open();
2130→                            Thread.Sleep(100);  // 포트 안정화 대기
2131→
2132→                            DateTime startTime = DateTime.Now;
2133→                            bool v1Detected = false;
2134→                            bool v2Detected = false;
2135→
2136→                            // 1초간 데이터 수신 시도
2137→                            while ((DateTime.Now - startTime).TotalMilliseconds < 1000)
2138→                            {
2139→                                // V2 바이너리 프로토콜 확인 (0x52 헤더)
2140→                                if (testPort.BytesToRead > 0)
2141→                                {
2142→                                    byte[] buffer = new byte[testPort.BytesToRead];
2143→                                    testPort.Read(buffer, 0, buffer.Length);
2144→
2145→                                    // V2 패턴 확인 (0x52 헤더)
2146→                                    for (int i = 0; i < buffer.Length; i++)
2147→                                    {
2148→                                        if (buffer[i] == 0x52)
2149→                                        {
2150→                                            v2Detected = true;
2151→                                            break;
2152→                                        }
2153→                                    }
2154→
2155→                                    // V1 패턴 확인 (텍스트 "S...E")
2156→                                    string text = System.Text.Encoding.ASCII.GetString(buffer);
2157→                                    if (text.Contains("S") && text.Contains("E"))
2158→                                    {
2159→                                        // "S"로 시작하고 "E"로 끝나는 34자리 문자열 확인
2160→                                        int sIndex = text.IndexOf('S');
2161→                                        int eIndex = text.IndexOf('E', sIndex);
2162→                                        if (sIndex >= 0 && eIndex > sIndex && (eIndex - sIndex + 1) == 34)
2163→                                        {
2164→                                            v1Detected = true;
2165→                                            break;
2166→                                        }
2167→                                    }
2168→
2169→                                    if (v1Detected || v2Detected)
2170→                                        break;
2171→                                }
2172→
2173→                                Thread.Sleep(10);
2174→                            }
2175→
2176→                            testPort.Close();
2177→
2178→                            // 버전 확인
2179→                            if (v2Detected)
2180→                            {
2181→                                foundPort = port;
2182→                                foundVersion = "2.0";
2183→                                this.Invoke(new MethodInvoker(() =>
2184→                                {
2185→                                    Logger.Log(LanguageManager.Get("port_found_v2", port));
2186→                                }));
2187→                                break;
2188→                            }
2189→                            else if (v1Detected)
2190→                            {
2191→                                foundPort = port;
2192→                                foundVersion = "1.0";
2193→                                this.Invoke(new MethodInvoker(() =>
2194→                                {
2195→                                    Logger.Log(LanguageManager.Get("port_found_v1", port));
2196→                                }));
2197→                                break;
2198→                            }
2199→                        }
2200→                        catch (Exception ex)
2201→                        {
2202→                            // 포트 접근 실패 (다른 프로그램에서 사용 중이거나 존재하지 않음)
2203→                            this.Invoke(new MethodInvoker(() =>
2204→                            {
2205→                                Logger.Log(LanguageManager.Get("port_access_fail", port, ex.Message));
2206→                            }));
2207→                        }
2208→                    }
2209→
2210→                    // 결과 처리
2211→                    this.Invoke(new MethodInvoker(() =>
2212→                    {
2213→                        if (foundPort != null)
2214→                        {
2215→                            // config.ini에 저장
2216→                            GlobalValues.aduinoPort = foundPort;
2217→                            GlobalValues.aduinoSwVer = foundVersion;
2218→                            GlobalValues.SaveChannelSettingsToIni();
2219→
2220→                            MessageBox.Show(
2221→                                LanguageManager.Get("port_found_msg", foundPort, foundVersion),
2222→                                LanguageManager.Get("port_found_title"),
2223→                                MessageBoxButtons.OK,
2224→                                MessageBoxIcon.Information
2225→                            );
2226→
2227→                            Logger.Log(LanguageManager.Get("port_saved", foundPort, foundVersion));
2228→
2229→                            // 시리얼 포트 재시작
2230→                            try
2231→                            {
2232→                                if (SerialAduino.IsOpen)
2233→                                    SerialAduino.Close();
2234→
2235→                                SerialAduino.PortName = foundPort;
2236→                                SerialAduino.Open();
2237→
2238→                                if (Trd1 != null && Trd1.IsAlive)
2239→                                    Trd1.Abort();
2240→
2241→                                Trd1 = new Thread(new ThreadStart(ThreadTask1));
2242→                                Trd1.IsBackground = true;
2243→                                Trd1.Start();
2244→
2245→                                Logger.Log(LanguageManager.Get("port_restart_ok"));
2246→                            }
2247→                            catch (Exception ex)
2248→                            {
2249→                                Logger.Log(LanguageManager.Get("port_restart_fail", ex.Message));
2250→                            }
2251→                        }
2252→                        else
2253→                        {
2254→                            MessageBox.Show(
2255→                                LanguageManager.Get("port_not_found_msg"),
2256→                                LanguageManager.Get("port_not_found_title"),
2257→                                MessageBoxButtons.OK,
2258→                                MessageBoxIcon.Warning
2259→                            );
2260→
2261→                            Logger.Log(LanguageManager.Get("port_not_found"));
2262→                        }
2263→
2264→                        button15.Enabled = true;
2265→                    }));
2266→                }
2267→                catch (Exception ex)
2268→                {
2269→                    this.Invoke(new MethodInvoker(() =>
2270→                    {
2271→                        MessageBox.Show(
2272→                            LanguageManager.Get("port_error_msg", ex.Message),
2273→                            LanguageManager.Get("port_error_title"),
2274→                            MessageBoxButtons.OK,
2275→                            MessageBoxIcon.Error
2276→                        );
2277→                        Logger.Log(LanguageManager.Get("port_scan_error", ex.Message));
2278→                        button15.Enabled = true;
2279→                    }));
2280→                }
2281→            });
2282→        }
