3220→        /// <summary>
3221→        /// JIG 1~128번까지 자동 초기화
3222→        /// </summary>
3223→        private void InitializeJig31()
3224→        {
3225→            try
3226→            {
3227→                using (var conn = new OleDbConnection(GlobalValues.gConString_Part))
3228→                {
3229→                    conn.Open();
3230→
3231→                    // 기존 JIG ID 목록 가져오기
3232→                    var existingJigIds = new HashSet<string>();
3233→                    using (var cmd = new OleDbCommand("SELECT Jig_ID FROM Table_Jig", conn))
3234→                    using (var reader = cmd.ExecuteReader())
3235→                    {
3236→                        while (reader.Read())
3237→                        {
3238→                            existingJigIds.Add(reader["Jig_ID"].ToString());
3239→                        }
3240→                    }
3241→
3242→                    // 1~128번 중 없는 JIG만 추가 (기존 데이터 보존)
3243→                    int addedCount = 0;
3244→                    for (int jigNum = 1; jigNum <= 128; jigNum++)
3245→                    {
3246→                        string jigId = jigNum.ToString();  // "1", "2", ... "128"
3247→
3248→                        if (existingJigIds.Contains(jigId))
3249→                            continue;  // 이미 있으면 스킵 (기존 데이터 보존)
3250→
3251→                        string ioOption;
3252→                        if (jigNum <= 64)
3253→                        {
3254→                            var channels = new List<string>();
3255→                            for (int bit = 0; bit < 6; bit++)
3256→                                if ((jigNum & (1 << bit)) != 0) channels.Add((bit + 1).ToString());
3257→                            ioOption = string.Join("/", channels);
3258→                        }
3259→                        else
3260→                            ioOption = "";  // 65~128: 미사용
3261→
3262→                        using (var insertCmd = new OleDbCommand(
3263→                            "INSERT INTO Table_Jig (Jig_ID, PartNo, PartName, ioOption) VALUES (?, ?, ?, ?)", conn))
3264→                        {
3265→                            insertCmd.Parameters.AddWithValue("?", jigId);
3266→                            insertCmd.Parameters.AddWithValue("?", "-");
3267→                            insertCmd.Parameters.AddWithValue("?", "-");
3268→                            insertCmd.Parameters.AddWithValue("?", ioOption);
3269→                            insertCmd.ExecuteNonQuery();
3270→                            addedCount++;
3271→                        }
3272→                    }
3273→
3274→                    if (addedCount > 0)
3275→                        System.Diagnostics.Debug.WriteLine($"JIG {addedCount}개 추가 (기존 데이터 보존)");
3276→                }
3277→            }
3278→            catch (Exception ex)
3279→            {
3280→                System.Diagnostics.Debug.WriteLine($"JIG 초기화 오류: {ex.Message}");
3281→            }
3282→        }
