351→        // v2.0 바이너리 프로토콜 (신규)
352→        private void ThreadTask1_V2()
353→        {
354→            byte[] buffer = new byte[12];  // 패킷 크기: Header(1) + DI(2) + AI(8) + Checksum(1)
355→            int readIndex = 0;
356→
357→            while (SerialAduino.IsOpen)
358→            {
359→                try
360→                {
361→                    int available = SerialAduino.BytesToRead;
362→                    if (available > 0)
363→                    {
364→                        // 헤더 찾기
365→                        if (readIndex == 0)
366→                        {
367→                            byte b = (byte)SerialAduino.ReadByte();
368→                            if (b == 0x52)  // 헤더 확인
369→                            {
370→                                buffer[0] = b;
371→                                readIndex = 1;
372→                            }
373→                        }
374→                        else
375→                        {
376→                            // 나머지 패킷 읽기
377→                            int bytesToRead = Math.Min(12 - readIndex, available);
378→                            int bytesRead = SerialAduino.Read(buffer, readIndex, bytesToRead);
379→                            readIndex += bytesRead;
380→
381→                            // 패킷 완성되면 파싱
382→                            if (readIndex >= 12)
383→                            {
384→                                // 체크섬 검증
385→                                byte checksum = 0;
386→                                for (int i = 1; i < 11; i++)  // Header와 Checksum 제외
387→                                {
388→                                    checksum ^= buffer[i];
389→                                }
390→
391→                                if (checksum == buffer[11])
392→                                {
393→                                    // DI 파싱 (Little Endian, 16비트 전체)
394→                                    ushort diValue = (ushort)(buffer[1] | (buffer[2] << 8));
395→                                    for (int i = 0; i < 16; i++)
396→                                    {
397→                                        IO.IN[i] = ((diValue >> i) & 1) == 1;
398→                                    }
399→
400→                                    // UI 업데이트 - btnIn은 8개만
401→                                    this.BeginInvoke(new MethodInvoker(() =>
402→                                    {
403→                                        for (int i = 0; i < btnIn.Length; i++)
404→                                        {
405→                                            if (IO.IN[i])
406→                                            {
407→                                                btnIn[i].BackColor = pColor.Theme.LightRed;
408→                                                btnIn[i].ForeColor = System.Drawing.Color.Black;
409→                                            }
410→                                            else
411→                                            {
412→                                                btnIn[i].BackColor = pColor.Theme.DeepRed;
413→                                                btnIn[i].ForeColor = System.Drawing.Color.White;
414→                                            }
415→                                        }
416→                                    }));
417→
418→                                    // AI 파싱 (Little Endian)
419→                                    ushort ai0 = (ushort)(buffer[3] | (buffer[4] << 8));
420→                                    ushort ai1 = (ushort)(buffer[5] | (buffer[6] << 8));
421→                                    ushort ai2 = (ushort)(buffer[7] | (buffer[8] << 8));
422→                                    ushort ai3 = (ushort)(buffer[9] | (buffer[10] << 8));
423→
424→                                    // ADC 값 -> 실제 물리값 변환 (모드별 분기)
425→                                    if (GlobalValues.weldMode == "SPOT")
426→                                    {
427→                                        // SPOT 모드: 전류/온도/공압 (전류 단위: kA)
428→                                        double ampRaw = (ai0 / 1023.0 * 3.0) * Amp.Tol;
429→                                        double tempRaw = ((ai1 / 1023.0 * 25.0) - 25.0) * Volt.Tol;
430→                                        double airRaw = (((ai2 / 1023.0 * 0.25) - 0.25) * 10.204) * Flow.Tol;
431→
432→                                        Amp.Value = Math.Max(0, Math.Round(AmpFilter.Update(ampRaw), 1));
433→                                        Volt.Value = Math.Max(0, Math.Round(VoltFilter.Update(tempRaw), 1));
434→                                        Flow.Value = Math.Max(0, Math.Round(FlowFilter.Update(airRaw), 1));
435→                                    }
436→                                    else
437→                                    {
438→                                        // CO2 모드: 전류/전압/유량
439→                                        double ampRaw = (ai0 / 1023.0 * 60.0) * Amp.Tol;
440→                                        double voltRaw = (ai1 / 1023.0 * 25.0) * Volt.Tol;
441→                                        double flowRaw = ((ai2 / 1023.0 * 12.5) - 12.5) * Flow.Tol;
442→
443→                                        Amp.Value = Math.Max(0, Math.Round(AmpFilter.Update(ampRaw), 1));
444→                                        Volt.Value = Math.Max(0, Math.Round(VoltFilter.Update(voltRaw), 1));
445→                                        Flow.Value = Math.Max(0, Math.Round(FlowFilter.Update(flowRaw), 1));
446→                                    }
447→
448→                                    labelAmp.Invoke(new MethodInvoker(() =>
449→                                    {
450→                                        labelAmp.Text = $"{Amp.Value.ToString("0.00")}";
451→                                        labelVolt.Text = $"{Volt.Value.ToString("0.00")}";
452→                                        labelFlow.Text = $"{Flow.Value.ToString("0.00")}";
453→                                    }));
454→                                }
455→                                else
456→                                {
457→                                    Logger.Log(LanguageManager.Get("log_checksum_error"));
458→                                }
459→
460→                                readIndex = 0;  // 다음 패킷 대기
461→                            }
462→                        }
463→                    }
464→                }
465→                catch (Exception ex)
466→                {
467→                    Logger.Log(LanguageManager.Get("log_v2_protocol_error", ex.Message));
468→                    readIndex = 0;  // 에러 시 초기화
469→                }
470→                Thread.Sleep(1);
471→            }
472→        }
