683→        /// <summary>
684→        /// ioOption 값으로 IO 조건 체크
685→        /// ioOption 형식: 슬래시 구분 채널 목록 (예: "1/3" → IN[1]=ON, IN[3]=ON 필요)
686→        /// 지정된 채널만 ON이고, 나머지 채널(1~6)은 OFF여야 매칭
687→        /// </summary>
688→        private bool CheckIOCondition(string setting, bool[] IN)
689→        {
690→            if (string.IsNullOrWhiteSpace(setting))
691→                return false;
692→
693→            // 슬래시로 분리하여 필요한 채널 목록 파싱
694→            var requiredChannels = new HashSet<int>();
695→            foreach (var part in setting.Split('/'))
696→            {
697→                if (int.TryParse(part.Trim(), out int ch) && ch >= 1 && ch <= 6)
698→                {
699→                    requiredChannels.Add(ch);
700→                }
701→            }
702→
703→            if (requiredChannels.Count == 0)
704→                return false;
705→
706→            // 채널 1~6 검사: 필요한 채널은 ON, 나머지는 OFF여야 함 (6비트 = 64개)
707→            for (int ch = 1; ch <= 6; ch++)
708→            {
709→                bool shouldBeOn = requiredChannels.Contains(ch);
710→                bool isOn = IN[ch];
711→
712→                if (shouldBeOn && !isOn) return false;  // 필요한 채널이 OFF
713→                if (!shouldBeOn && isOn) return false;  // 불필요한 채널이 ON
714→            }
715→
716→            return true;
717→        }
