private void LoadAllPointData()
{
    var conn = new OleDbConnection(GlobalValues.gConString_Part);
    conn.Open();

    var cmd = new OleDbCommand("SELECT * FROM Table_Seq ORDER BY JIG_ID, LEN(POINT_ID), POINT_ID", conn);
    var reader = cmd.ExecuteReader();

    string currentJigId = "";
    var buffer = new List<Dictionary<string, object>>();

    while (reader.Read())
    {
        string jigId = reader["JIG_ID"].ToString();

        if (currentJigId != "" && currentJigId != jigId)
        {
            PointDataManager.All[currentJigId] = ConvertToPointData(buffer);
            buffer.Clear();
        }

        var row = new Dictionary<string, object>();
        for (int i = 0; i < reader.FieldCount; i++)
            row[reader.GetName(i)] = reader.GetValue(i);

        buffer.Add(row);
        currentJigId = jigId;
    }

    if (buffer.Count > 0)
        PointDataManager.All[currentJigId] = ConvertToPointData(buffer);

    conn.Close();
}
private void LoadJigData()
{
    JigDataManager.All.Clear();

    var conn = new OleDbConnection(GlobalValues.gConString_Part);
    conn.Open();

    var cmd = new OleDbCommand("SELECT * FROM Table_Jig", conn);
    var reader = cmd.ExecuteReader();

    while (reader.Read())
    {
        var info = new JigInfo
        {
            PartNo = reader["PartNo"].ToString(),
            PartName = reader["PartName"].ToString(),
            ioOption = reader["ioOption"].ToString(),
            Jig_ID = reader["Jig_ID"].ToString(),
            Code4M = reader["Code4M"].ToString(),
            EoNumber = reader["EoNumber"].ToString(),
            BarcodeSizeOffset = reader["BarcodeSizeOffset"].ToString(),
            ImagePath = reader["ImagePath"].ToString()
        };

        JigDataManager.All.Add(info);
    }

    conn.Close();
    Logger.Log($"[JIG] {JigDataManager.All.Count}개 JIG 로드 완료");
}
private PointData ConvertToPointData(List<Dictionary<string, object>> rows)
{
    int count = rows.Count;
    var pd = new PointData
    {
        Basic1_Min = new double[count],
        Basic1_Max = new double[count],
        Basic2_Min = new double[count],
        Basic2_Max = new double[count],
        Basic3_Min = new double[count],
        Basic3_Max = new double[count],

        Basic1_Type = new string[count],
        Basic2_Type = new string[count],
        Basic3_Type = new string[count],

        Shape_X = new double[count],
        Shape_Y = new double[count],
        Shape_W = new double[count],
        Shape_H = new double[count],

        Check_Pass = new bool[count],
        Point_OK = new int[count],

        OffSet1 = new double[count],
        OffSet2 = new double[count],
        OffSet3 = new double[count],

        StartSector = new double[count],
        EndSector = new double[count],
        graphWidth = new double[count],
    };

    for (int i = 0; i < count; i++)
    {
        var row = rows[i];

        pd.Basic1_Min[i] = ToDouble(row["Value1_Min"]);
        pd.Basic1_Max[i] = ToDouble(row["Value1_Max"]);
        pd.Basic2_Min[i] = ToDouble(row["Value2_Min"]);
        pd.Basic2_Max[i] = ToDouble(row["Value2_Max"]);
        pd.Basic3_Min[i] = ToDouble(row["Value3_Min"]);
        pd.Basic3_Max[i] = ToDouble(row["Value3_Max"]);

        pd.Basic1_Type[i] = row["Value1_Type"]?.ToString();
        pd.Basic2_Type[i] = row["Value2_Type"]?.ToString();
        pd.Basic3_Type[i] = row["Value3_Type"]?.ToString();

        pd.Shape_X[i] = ToDouble(row["Image_Coord_X"]);
        pd.Shape_Y[i] = ToDouble(row["Image_Coord_Y"]);
        pd.Shape_W[i] = ToDouble(row["Image_Size_X"]);
        pd.Shape_H[i] = ToDouble(row["Image_Size_Y"]);

        pd.Check_Pass[i] = row["Pass"] != DBNull.Value && Convert.ToDouble(row["Pass"]) > 0;
        pd.Point_OK[i] = 0;

        pd.OffSet1[i] = ToDouble(row["Value1_Tol"]);
        pd.OffSet2[i] = ToDouble(row["Value2_Tol"]);
        pd.OffSet3[i] = ToDouble(row["Value3_Tol"]);

        pd.StartSector[i] = ToDouble(row["StartSector"]);
        pd.EndSector[i] = ToDouble(row["EndSector"]);
        pd.graphWidth[i] = ToDouble(row["graphWidth"]);

    }

    return pd;
}
public static bool CheckIoMatch(string ioOption)
{
    if (string.IsNullOrWhiteSpace(ioOption))
        return false;

    string[] parts = ioOption.Split('/');
    foreach (string part in parts)
    {
        if (int.TryParse(part, out int index))
        {
            if (index < 0 || index >= IO.IN.Length)
                return false;

            if (!IO.IN[index])
                return false; // 조건 안 맞으면 바로 false
        }
        else
        {
            return false; // 잘못된 문자열
        }
    }

    return true;
}
private double ToDouble(object obj)
{
    return obj == DBNull.Value ? 0 : Convert.ToDouble(obj);
}

