private void button15_Click(object sender, EventArgs e)
{
    // 자동 포트 탐색 시작
    button15.Enabled = false;
    Logger.Log(LanguageManager.Get("port_scan_start"));

    Task.Run(() =>
    {
        try
        {
            // 기존 포트 닫기
            if (SerialAduino.IsOpen)
            {
                SerialAduino.Close();
                Thread.Sleep(500);
            }

            string foundPort = null;
            string foundVersion = null;

            // COM 포트 목록 가져오기
            string[] ports = SerialPort.GetPortNames();
            Array.Sort(ports);  // COM1, COM2, ... 순서대로 정렬

            foreach (string port in ports)
            {
                this.Invoke(new MethodInvoker(() =>
                {
                    Logger.Log(LanguageManager.Get("port_checking", port));
                }));

                try
                {
                    // 포트 열기 (Arduino는 115200 baud)
                    SerialPort testPort = new SerialPort(port, 115200);
                    testPort.Open();
                    Thread.Sleep(100);  // 포트 안정화 대기

                    DateTime startTime = DateTime.Now;
                    bool v1Detected = false;
                    bool v2Detected = false;

                    // 1초간 데이터 수신 시도
                    while ((DateTime.Now - startTime).TotalMilliseconds < 1000)
                    {
                        // V2 바이너리 프로토콜 확인 (0x52 헤더)
                        if (testPort.BytesToRead > 0)
                        {
                            byte[] buffer = new byte[testPort.BytesToRead];
                            testPort.Read(buffer, 0, buffer.Length);

                            // V2 패턴 확인 (0x52 헤더)
                            for (int i = 0; i < buffer.Length; i++)
                            {
                                if (buffer[i] == 0x52)
                                {
                                    v2Detected = true;
                                    break;
                                }
                            }

                            // V1 패턴 확인 (텍스트 "S...E")
                            string text = System.Text.Encoding.ASCII.GetString(buffer);
                            if (text.Contains("S") && text.Contains("E"))
                            {
                                // "S"로 시작하고 "E"로 끝나는 34자리 문자열 확인
                                int sIndex = text.IndexOf('S');
                                int eIndex = text.IndexOf('E', sIndex);
                                if (sIndex >= 0 && eIndex > sIndex && (eIndex - sIndex + 1) == 34)
                                {
                                    v1Detected = true;
                                    break;
                                }
                            }

                            if (v1Detected || v2Detected)
                                break;
                        }

                        Thread.Sleep(10);
                    }

                    testPort.Close();

                    // 버전 확인
                    if (v2Detected)
                    {
                        foundPort = port;
                        foundVersion = "2.0";
                        this.Invoke(new MethodInvoker(() =>
                        {
                            Logger.Log(LanguageManager.Get("port_found_v2", port));
                        }));
                        break;
                    }
                    else if (v1Detected)
                    {
                        foundPort = port;
                        foundVersion = "1.0";
                        this.Invoke(new MethodInvoker(() =>
                        {
                            Logger.Log(LanguageManager.Get("port_found_v1", port));
                        }));
                        break;
                    }
                }
                catch (Exception ex)
                {
                    // 포트 접근 실패 (다른 프로그램에서 사용 중이거나 존재하지 않음)
                    this.Invoke(new MethodInvoker(() =>
                    {
                        Logger.Log(LanguageManager.Get("port_access_fail", port, ex.Message));
                    }));
                }
            }

            // 결과 처리
            this.Invoke(new MethodInvoker(() =>
            {
                if (foundPort != null)
                {
                    // config.ini에 저장
                    GlobalValues.aduinoPort = foundPort;
                    GlobalValues.aduinoSwVer = foundVersion;
                    GlobalValues.SaveChannelSettingsToIni();

                    MessageBox.Show(
                        LanguageManager.Get("port_found_msg", foundPort, foundVersion),
                        LanguageManager.Get("port_found_title"),
                        MessageBoxButtons.OK,
                        MessageBoxIcon.Information
                    );

                    Logger.Log(LanguageManager.Get("port_saved", foundPort, foundVersion));

                    // 시리얼 포트 재시작
                    try
                    {
                        if (SerialAduino.IsOpen)
                            SerialAduino.Close();

                        SerialAduino.PortName = foundPort;
                        SerialAduino.Open();

                        if (Trd1 != null && Trd1.IsAlive)
                            Trd1.Abort();

                        Trd1 = new Thread(new ThreadStart(ThreadTask1));
                        Trd1.IsBackground = true;
                        Trd1.Start();

                        Logger.Log(LanguageManager.Get("port_restart_ok"));
                    }
                    catch (Exception ex)
                    {
                        Logger.Log(LanguageManager.Get("port_restart_fail", ex.Message));
                    }
                }
                else
                {
                    MessageBox.Show(
                        LanguageManager.Get("port_not_found_msg"),
                        LanguageManager.Get("port_not_found_title"),
