/// <summary>
/// 테스트용 - Jig_ID로 직접 DB 저장
/// </summary>
private bool AutoRegisterToDbDirect(string jigId, int pointCount,
    List<List<double>> ampData, List<List<double>> voltData, List<List<double>> flowData)
{
    try
    {
        using (var conn = new OleDbConnection(GlobalValues.gConString_Part))
        {
            conn.Open();

            // 기존 포인트 삭제
            using (var cmd = new OleDbCommand("DELETE FROM Table_Seq WHERE Jig_ID = ?", conn))
            {
                cmd.Parameters.AddWithValue("?", jigId);
                cmd.ExecuteNonQuery();
            }

            bool isSpotMode = GlobalValues.weldMode == "SPOT";

            for (int i = 0; i < pointCount; i++)
            {
                int newPointId = i + 1;

                if (ampData[i] == null || ampData[i].Count == 0) continue;

                double baseAmp = isSpotMode ? ampData[i].Max() : ampData[i].Average();
                double baseVolt = isSpotMode ? voltData[i].Max() : voltData[i].Average();
                double baseFlow = flowData[i].Max();

                using (var cmd = new OleDbCommand(@"
                    INSERT INTO Table_Seq
                    (Jig_ID, Point_ID, Value1_Max, Value1_Min, Value2_Max, Value2_Min, Value3_Max, Value3_Min,
                     Value1_Tol, Value2_Tol, Value3_Tol, Value1_Type, Value2_Type, Value3_Type,
                     StartSector, EndSector, Pass, Image_Coord_X, Image_Coord_Y, Image_Size_X, Image_Size_Y, graphWidth)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)", conn))
                {
                    cmd.Parameters.AddWithValue("?", jigId);
                    cmd.Parameters.AddWithValue("?", newPointId.ToString());
                    cmd.Parameters.AddWithValue("?", Math.Round(baseAmp * 1.3, 2));
                    cmd.Parameters.AddWithValue("?", Math.Round(baseAmp * 0.7, 2));
                    cmd.Parameters.AddWithValue("?", Math.Round(baseVolt * 1.3, 2));
                    cmd.Parameters.AddWithValue("?", Math.Round(baseVolt * 0.7, 2));
                    cmd.Parameters.AddWithValue("?", Math.Round(baseFlow * 1.3, 2));
                    cmd.Parameters.AddWithValue("?", Math.Round(baseFlow * 0.7, 2));
                    cmd.Parameters.AddWithValue("?", 1);
                    cmd.Parameters.AddWithValue("?", 1);
                    cmd.Parameters.AddWithValue("?", 1);
                    cmd.Parameters.AddWithValue("?", isSpotMode ? "Max" : "Average");
                    cmd.Parameters.AddWithValue("?", isSpotMode ? "Max" : "Average");
                    cmd.Parameters.AddWithValue("?", "Max");
                    cmd.Parameters.AddWithValue("?", isSpotMode ? 0 : 5);  // StartSector (SPOT: 0%, CO2: 5% trim)
                    cmd.Parameters.AddWithValue("?", isSpotMode ? 0 : 5);  // EndSector (SPOT: 0%, CO2: 5% trim)
                    cmd.Parameters.AddWithValue("?", 1);
                    cmd.Parameters.AddWithValue("?", 0);
                    cmd.Parameters.AddWithValue("?", 0);
                    cmd.Parameters.AddWithValue("?", 0);
                    cmd.Parameters.AddWithValue("?", 0);
                    cmd.Parameters.AddWithValue("?", 100);
                    cmd.ExecuteNonQuery();
                }
            }
            Logger.Log($"[테스트] Jig_ID={jigId}에 {pointCount}개 포인트 저장됨");
            return true;
        }
    }
    catch (Exception ex)
    {
        Logger.Log($"[테스트] 저장 오류: {ex.Message}");
        return false;
    }
}

/// <summary>
/// JIG 1~128번까지 자동 초기화
/// </summary>
private void InitializeJig31()
{
    try
    {
        using (var conn = new OleDbConnection(GlobalValues.gConString_Part))
        {
            conn.Open();

            // 기존 JIG ID 목록 가져오기
            var existingJigIds = new HashSet<string>();
            using (var cmd = new OleDbCommand("SELECT Jig_ID FROM Table_Jig", conn))
            using (var reader = cmd.ExecuteReader())
            {
                while (reader.Read())
                {
                    existingJigIds.Add(reader["Jig_ID"].ToString());
                }
            }

            // 1~128번 중 없는 JIG만 추가 (기존 데이터 보존)
            int addedCount = 0;
            for (int jigNum = 1; jigNum <= 128; jigNum++)
            {
                string jigId = jigNum.ToString();  // "1", "2", ... "128"

                if (existingJigIds.Contains(jigId))
                    continue;  // 이미 있으면 스킵 (기존 데이터 보존)

                string ioOption;
                if (jigNum <= 64)
                {
                    var channels = new List<string>();
                    for (int bit = 0; bit < 6; bit++)
                        if ((jigNum & (1 << bit)) != 0) channels.Add((bit + 1).ToString());
                    ioOption = string.Join("/", channels);
                }
                else
                    ioOption = "";  // 65~128: 미사용

                using (var insertCmd = new OleDbCommand(
                    "INSERT INTO Table_Jig (Jig_ID, PartNo, PartName, ioOption) VALUES (?, ?, ?, ?)", conn))
                {
                    insertCmd.Parameters.AddWithValue("?", jigId);
                    insertCmd.Parameters.AddWithValue("?", "-");
                    insertCmd.Parameters.AddWithValue("?", "-");
                    insertCmd.Parameters.AddWithValue("?", ioOption);
                    insertCmd.ExecuteNonQuery();
                    addedCount++;
                }
            }

            if (addedCount > 0)
                System.Diagnostics.Debug.WriteLine($"JIG {addedCount}개 추가 (기존 데이터 보존)");
        }
    }
    catch (Exception ex)
    {
        System.Diagnostics.Debug.WriteLine($"JIG 초기화 오류: {ex.Message}");
    }
}

/// <summary>
/// 숫자를 ioOption 형식으로 변환 (5비트 바이너리)
/// 예: 1→"1", 3→"1/2", 16→"5", 31→"1/2/3/4/5"
/// </summary>
private string GetIoOptionFromNumber(int num)
{
    List<int> bits = new List<int>();
    for (int i = 0; i < 5; i++)
    {
        if ((num & (1 << i)) != 0)
            bits.Add(i + 1);  // 1-based (IO.IN[1]~IO.IN[5])
    }
    return string.Join("/", bits);
}

