using ScottPlot;
using System;
using System.Collections.Generic;
using System.Drawing;
using System.Linq;
using System.Threading;
using System.Windows.Forms;

namespace WeldMonitor3
{
    public partial class _FrmMain
    {
        // ===== 검사 상태머신 (ThreadTask2) + 판정 로직 =====

        private void ThreadTask2()
        {
            int seqcount = 0;
            bool hasSavedPartialResult = false;
            bool lastCycleIsAllOK = true;

            List<double> timeList = new List<double>();
            List<double> ampList = new List<double>();
            List<double> voltList = new List<double>();
            List<double> flowList = new List<double>();

            while (true)
            {
                try
                {
                if (flagStart == true)
                {
                    // 자동설정 모드일 때는 ThreadTask2 동작 안 함
                    if (_autoSetMode)
                    {
                        Thread.Sleep(100);
                        continue;
                    }

                    if (label4.InvokeRequired)
                    {
                        label4.Invoke((MethodInvoker)(() =>
                        {
                            label4.Text = GlobalValues.wstep.ToString();
                        }));
                    }

                    if (labelAmp.InvokeRequired)
                    {
                        labelAmp.Invoke((MethodInvoker)(() =>
                        {
                            labelAmp.Text = Amp.Value.ToString("0.00");
                            labelVolt.Text = Volt.Value.ToString("0.00");
                            labelFlow.Text = Flow.Value.ToString("0.00");
                        }));
                    }

                    // IO OFF 상태 + 일부 포인트가 진행된 경우 → 중간 저장
                    bool isJigSignalOff = !IO.IN[0] && !IO.IN[1] && !IO.IN[2] && !IO.IN[3] && !IO.IN[4] && !IO.IN[5] && !IO.IN[6];

                    if (isJigSignalOff)
                    {
                        _jigOffDebounceCount++;
                        _jigOnDebounceCount = 0;  // ON 카운터 리셋
                        // 디바운싱: 연속 OFF 횟수가 임계값 이상일 때만 리셋
                        if (_jigOffDebounceCount >= JIG_DEBOUNCE_THRESHOLD)
                        {
                            if (GlobalValues.wstep != 0)
                            {
                                Logger.Log($"[STEP {GlobalValues.wstep}→0] IO 신호 전체 OFF 감지 - 대기 상태로 리셋");
                                GlobalValues.wstep = 0;
                            }

                            if (seqcount > 0 && !hasSavedPartialResult)
                            {
                                bool isAllOK = data.Point_OK.Take(seqcount).All(p => p == 1);
                                UpdateDecisionLabel(isAllOK);
                                SaveResultFromGrid(isAllOK);
                                Logger.Log($"[중간저장] 진행된 포인트 {seqcount}개 중간 저장 완료");
                                hasSavedPartialResult = true;
                            }
                        }
                    }
                    else
                    {
                        // JIG 신호 ON이면 OFF 카운터 리셋, ON 카운터 증가
                        _jigOffDebounceCount = 0;
                        _jigOnDebounceCount++;
                    }

                    switch (GlobalValues.wstep)
                    {
                        case 0:
                            JigInfo detectedJig = null;

                            // Arduino IO 모드: ioOption으로 JIG 감지
                            foreach (var item in JigDataManager.GetEnabledJigs())
                            {
                                string ioOption = item.ioOption?.Trim();

                                if (string.IsNullOrWhiteSpace(ioOption))
                                    continue;

                                if (!CheckIOCondition(ioOption, IO.IN))
                                    continue;

                                detectedJig = item;
                                break;
                            }

                            // 디바운싱: 연속 ON 횟수가 임계값 이상일 때만 JIG 감지
                            if (detectedJig != null && _jigOnDebounceCount >= JIG_DEBOUNCE_THRESHOLD)
                            {
                                seqcount = 0;
                                hasSavedPartialResult = false; // 초기화
                                jig = detectedJig;
                                Logger.Log($"[STEP 0→1] JIG 신호 감지 - jigID: {jig.Jig_ID}, partNo: {jig.PartNo}");

                                if (labelPArtNo.InvokeRequired)
                                {
                                    labelPArtNo.Invoke((MethodInvoker)(() =>
                                    {
                                        labelPArtNo.Text = jig.PartNo.ToString();
                                    }));
                                }
                                if (labelPArtName.InvokeRequired)
                                {
                                    labelPArtName.Invoke((MethodInvoker)(() =>
                                    {
                                        labelPArtName.Text = jig.PartName.ToString();
                                    }));
                                }

                                GlobalValues.wstep = 1;
                                _jigOnDebounceCount = 0;  // 전환 후 카운터 리셋
                            }
                            break;

                        case 1:
                            if (PointDataManager.All.TryGetValue(jig.Jig_ID, out data))
                            {
                                Logger.Log($"[STEP 1→2] 포인트 데이터 로드 - JIG_ID: {jig.Jig_ID}, 포인트 수: {data.Basic1_Min.Length}");

                                // seqcount 범위 체크 (방어 코드)
                                if (seqcount >= data.Basic1_Min.Length || seqcount < 0)
                                {
                                    Logger.Log($"[STEP 1] seqcount 범위 초과 ({seqcount}/{data.Basic1_Min.Length}) - wstep 0으로 리셋");
                                    GlobalValues.wstep = 0;
                                    break;
                                }

                                // Tol(Offset)이 0이면 1로 대체 (방어코드)
                                Amp.Tol = data.OffSet1[seqcount] == 0 ? 1 : data.OffSet1[seqcount];
                                Volt.Tol = data.OffSet2[seqcount] == 0 ? 1 : data.OffSet2[seqcount];
                                Flow.Tol = data.OffSet3[seqcount] == 0 ? 1 : data.OffSet3[seqcount];
                                LoadPic(jig.ImagePath);
                                InitControl();
                                pointRectangles.Clear();
                                pictureBox1.Invalidate();
                                // 원시데이터 리스트 초기화
                                rawDataList.Clear();
                                rawDataTimestamp = DateTime.Now.ToString("yyyyMMdd_HHmmss");
                                GlobalValues.wstep = 2;
                            }
                            break;

                        case 2:
                            // 용접 시작 감지
                            bool weldStartDetected = false;
                            if (GlobalValues.weldMode == "SPOT")
                            {
                                // SPOT 모드: 전류값으로 감지
                                weldStartDetected = (Amp.Value > GlobalValues.spotWeldThreshold);
                            }
                            else
                            {
                                // CO2 모드: DI 신호
                                weldStartDetected = IO.IN[0];
                            }

                            if (weldStartDetected)
                            {
                                Logger.Log($"[STEP 2→3] 용접 신호 ON 감지 - 측정 시작 (포인트 {seqcount + 1})");
                                // SPOT 모드는 X축 1초 고정, CO2 모드는 5초 고정
                                double xAxisWidth = (GlobalValues.weldMode == "SPOT") ? 1.0 : 5.0;
                                InitPlots(xAxisWidth);
                                bufferIndex = 0;
                                timeList.Clear();
                                voltList.Clear();
                                ampList.Clear();
                                flowList.Clear();
                                sw.Restart();

                                // 첫 샘플 저장 (wstep 2에서 감지한 순간의 데이터)
                                timeBuffer[bufferIndex] = 0.0;
                                ampBuffer[bufferIndex] = Amp.Value;
                                voltBuffer[bufferIndex] = Volt.Value;
                                flowBuffer[bufferIndex] = Flow.Value;
                                bufferIndex++;

                                GlobalValues.wstep = 3;
                            }
                            break;

                        case 3:
                            // 용접 중 감지
                            bool weldingInProgress = false;
                            if (GlobalValues.weldMode == "SPOT")
                            {
                                // SPOT 모드: 전류값으로 감지
                                weldingInProgress = (Amp.Value > GlobalValues.spotWeldThreshold);
                            }
                            else
                            {
                                // CO2 모드: DI 신호
                                weldingInProgress = IO.IN[0];
                            }

                            if (weldingInProgress)
                            {
                                if (bufferIndex < 50000)  // 배열 범위 체크 (최대 500초)
                                {
                                    timeBuffer[bufferIndex] = sw.Elapsed.TotalSeconds;
                                    ampBuffer[bufferIndex] = Amp.Value;
                                    voltBuffer[bufferIndex] = Volt.Value;
                                    flowBuffer[bufferIndex] = Flow.Value;

                                    for (int i = 0; i < formsPlots.Length; i++)
                                    {
                                        signalPlots[i].MaxRenderIndex = bufferIndex;
                                        int idx = i;
                                        formsPlots[idx].Invoke((MethodInvoker)(() =>
                                        {
                                            formsPlots[idx].Refresh();
                                        }));
                                    }

                                    bufferIndex++;
                                }
                                else
                                {
                                    // 버퍼 초과 → 강제 측정 완료
                                    sw.Stop();
                                    Logger.Log($"[STEP 3→4] 버퍼 초과 (50000 샘플, 500초) - 강제 측정 완료 (포인트 {seqcount + 1}, 측정시간: {sw.Elapsed.TotalSeconds:F1}s)");
                                    GlobalValues.wstep = 4;
                                }
                            }
                            else
                            {
                                sw.Stop();
                                Logger.Log($"[STEP 3→4] 용접 신호 OFF - 측정 완료 (포인트 {seqcount + 1}, 측정시간: {sw.Elapsed.TotalSeconds:F1}s, 샘플수: {bufferIndex})");
                                GlobalValues.wstep = 4;
                            }
                            break;

                        case 4:
                            // 샘플이 없으면 건너뛰기 (측정 데이터 없음)
                            if (bufferIndex == 0)
                            {
                                Logger.Log($"[STEP 4] 측정 데이터 없음 - 포인트 {seqcount + 1} 건너뜀");
                                bufferIndex = 0;
                                GlobalValues.wstep = 2;  // 다음 용접 대기
                                break;
                            }

                            // seqcount 범위 체크 (방어 코드)
                            if (seqcount >= data.Basic1_Min.Length || seqcount < 0)
                            {
                                Logger.Log($"[STEP 4] seqcount 범위 초과 ({seqcount}/{data.Basic1_Min.Length}) - 건너뜀");
                                GlobalValues.wstep = 2;
                                break;
                            }

                            double totalDuration = timeBuffer[bufferIndex - 1];
                            double startTime = totalDuration * data.StartSector[seqcount] / 100.0;
                            double endTime = totalDuration - (totalDuration * data.EndSector[seqcount] / 100.0);

                            var selectedIndices = Enumerable.Range(0, bufferIndex)
                                .Where(i => timeBuffer[i] >= startTime && timeBuffer[i] <= endTime)
                                .ToArray();

                            // 원본: selectedIndices가 비어있으면 Average/Max/Min에서 예외 발생
                            // 수정: 빈 배열이면 전체 버퍼 데이터 사용
                            if (selectedIndices.Length == 0)
                                selectedIndices = Enumerable.Range(0, bufferIndex).ToArray();

                            var ampValid = selectedIndices.Select(i => ampBuffer[i]).ToArray();
                            var voltValid = selectedIndices.Select(i => voltBuffer[i]).ToArray();
                            var flowValid = selectedIndices.Select(i => flowBuffer[i]).ToArray();

                            double ampAvr = Math.Round(ampValid.Average(), 2);
                            double ampMax = Math.Round(ampValid.Max(), 2);
                            double ampMin = Math.Round(ampValid.Min(), 2);

                            double voltAvr = Math.Round(voltValid.Average(), 2);
                            double voltMax = Math.Round(voltValid.Max(), 2);
                            double voltMin = Math.Round(voltValid.Min(), 2);

                            double flowAvr = Math.Round(flowValid.Average(), 2);
                            double flowMax = Math.Round(flowValid.Max(), 2);
                            double flowMin = Math.Round(flowValid.Min(), 2);

                            double elapsed = Math.Round(sw.Elapsed.TotalSeconds, 1);

                            WriteGrid(
                                dataGridView1,
                                int.Parse(jig.Jig_ID),
                                seqcount + 1,
                                data.Basic1_Min.Length,
                                data.Check_Pass[seqcount],
                                data.Basic1_Min[seqcount], ampAvr, data.Basic1_Max[seqcount], ampMax, ampMin, data.Basic1_Type[seqcount],
                                data.Basic2_Min[seqcount], voltAvr, data.Basic2_Max[seqcount], voltMax, voltMin, data.Basic2_Type[seqcount],
                                data.Basic3_Min[seqcount], flowAvr, data.Basic3_Max[seqcount], flowMax, flowMin, data.Basic3_Type[seqcount],
                                elapsed,
                                seqcount
                            );

                            pointRectangles.Add((new Rectangle(
                                (int)data.Shape_X[seqcount],
                                (int)data.Shape_Y[seqcount],
                                (int)data.Shape_W[seqcount],
                                (int)data.Shape_H[seqcount]), seqcount + 1));
                            pictureBox1.Invalidate();

                            // 판정 결과 로그
                            string pointResult = data.Point_OK[seqcount] == 1 ? "OK" : "NG";
                            Logger.Log($"[STEP 4→5] 판정 완료 - JIG[{jig.Jig_ID}] POINT[{seqcount + 1}/{data.Basic1_Min.Length}] 결과: {pointResult}");
                            Logger.Log($"  ▶ Amp: {ampAvr:F2}kA (범위: {data.Basic1_Min[seqcount]:F2}~{data.Basic1_Max[seqcount]:F2})");
                            Logger.Log($"  ▶ Volt: {voltAvr:F1}V (범위: {data.Basic2_Min[seqcount]:F1}~{data.Basic2_Max[seqcount]:F1})");
                            Logger.Log($"  ▶ Flow: {flowAvr:F1}L/min (범위: {data.Basic3_Min[seqcount]:F1}~{data.Basic3_Max[seqcount]:F1})");

                            // 원시데이터 누적 저장
                            var rawPoint = new RawPointData
                            {
                                Point = seqcount + 1,
                                AmpAvg = ampAvr, AmpMax = ampMax, AmpMin = ampMin,
                                VoltAvg = voltAvr, VoltMax = voltMax, VoltMin = voltMin,
                                FlowAvg = flowAvr, FlowMax = flowMax, FlowMin = flowMin,
                                Elapsed = elapsed,
                                Result = pointResult
                            };
                            for (int i = 0; i < bufferIndex; i++)
                            {
                                rawPoint.Time.Add(timeBuffer[i]);
                                rawPoint.Amp.Add(ampBuffer[i]);
                                rawPoint.Volt.Add(voltBuffer[i]);
                                rawPoint.Flow.Add(flowBuffer[i]);
                            }
                            rawDataList.Add(rawPoint);

                            GlobalValues.wstep = 5;
                            break;

                        case 5:
                            seqcount++;
                            if (seqcount >= data.Basic1_Min.Length)
                            {
                                Logger.Log($"[STEP 5→6] 모든 포인트 완료 ({seqcount}개) - 최종 판정 진행");
                                GlobalValues.wstep = 6;
                            }
                            else
                            {
                                Logger.Log($"[STEP 5→2] 다음 포인트 대기 ({seqcount + 1}/{data.Basic1_Min.Length})");
                                GlobalValues.wstep = 2;
                            }
                            break;

                        case 6:
                            {
                                bool isAllOK = data.Point_OK.All(p => p == 1);
                                int okCount = data.Point_OK.Count(p => p == 1);
                                int ngCount = data.Point_OK.Length - okCount;
                                string finalResult = isAllOK ? "OK" : "NG";

                                Logger.Log($"[STEP 6→7] 사이클 완료 - 최종판정: {finalResult} (OK: {okCount}, NG: {ngCount})");
                                UpdateDecisionLabel(isAllOK);
                                SaveResultFromGrid(isAllOK);
                                // 원시데이터 CSV 저장
                                SaveRawDataCsv(finalResult);
                                hasSavedPartialResult = true;
                                lastCycleIsAllOK = isAllOK;
                                seqcount = 0;
                                GlobalValues.wstep = 7;
                                break;
                            }

                        case 7:
                            // NG이고 Hold 옵션 사용 시에만 Hold 진입
                            if (!lastCycleIsAllOK && GlobalValues.HoldOption == "use")
                            {
                                Logger.Log($"[STEP 7→8] NG + Hold 옵션 사용 - NG 처리 대기");
                                GlobalValues.wstep = 8;
                            }
                            else
                            {
                                if (lastCycleIsAllOK)
                                    Logger.Log($"[STEP 7→100] OK - 대기 상태로 전환");
                                else
                                    Logger.Log($"[STEP 7→100] Hold 옵션 미사용 - 대기 상태로 전환");
                                GlobalValues.wstep = 100;
                            }
                            break;

                        case 8:
                            Logger.Log($"[STEP 8→9] Hold 신호 ON - NG 입력 대기");
                            try
                            {
                                this.Invoke((MethodInvoker)(() =>
                                {
                                    DoOn(GlobalValues.HoldSignal);
                                    LoadNg();
                                    ShowOnScreenKeyboard();
                                }));
                            }
                            catch (Exception ex8)
                            {
                                Logger.Log($"[STEP 8] 예외 (홀드/NG 화면): {ex8.Message}");
                            }
                            finally
                            {
                                GlobalValues.wstep = 9;
                            }
                            break;

                        case 9:
                            // ready ng handler
                            break;

                        case 10:
                            Logger.Log($"[STEP 10→100] Hold 신호 OFF - 대기 상태로 전환");
                            try
                            {
                                this.Invoke((MethodInvoker)(() =>
                                {
                                    DoOff(GlobalValues.HoldSignal);
                                }));
                            }
                            catch (Exception ex10)
                            {
                                Logger.Log($"[STEP 10] 예외 (Hold 해제): {ex10.Message}");
                            }
                            GlobalValues.wstep = 100;
                            break;

                        case 100:
                            // 사이클 완료 → 대기 상태로
                            GlobalValues.wstep = 0;
                            break;
                    }
                }

                Thread.Sleep(5);
                }
                catch (ThreadAbortException)
                {
                    break;
                }
                catch (Exception ex)
                {
                    Logger.Log($"[ThreadTask2] 예외: {ex.Message}");
                }
            }
        }

        private void WriteGrid(
            DataGridView grid,
            int jigId, int point, int totalPoint, bool passOption,
            double min1, double val1Avr, double max1, double val1Max, double val1Min, string type1,
            double min2, double val2Avr, double max2, double val2Max, double val2Min, string type2,
            double min3, double val3Avr, double max3, double val3Max, double val3Min, string type3,
            double elapsedTime, int wPoint)
        {

            if (grid.InvokeRequired)
            {
                grid.Invoke((MethodInvoker)(() => WriteGrid(
                    grid, jigId, point, totalPoint, passOption,
                    min1, val1Avr, max1, val1Max, val1Min, type1,
                    min2, val2Avr, max2, val2Max, val2Min, type2,
                    min3, val3Avr, max3, val3Max, val3Min, type3,
                    elapsedTime, wPoint)));
                return;
            }

            bool[] decision = new bool[3];
            double[] values = new double[3];

            // SPOT 모드 Volt/Flow 사용 여부
            bool useVolt = GlobalValues.weldMode != "SPOT" || GlobalValues.spotUseVolt;
            bool useFlow = GlobalValues.weldMode != "SPOT" || GlobalValues.spotUseFlow;

            // 1번 항목 판정 (Amp - 항상 사용)
            values[0] = (type1 == "Maximum" || type1 == "Max") ? val1Max : val1Avr;
            decision[0] = (values[0] >= min1 && values[0] <= max1);

            // 2번 항목 판정 (Volt/온도 - SPOT 모드에서 선택적)
            if (useVolt)
            {
                values[1] = (type2 == "Maximum" || type2 == "Max") ? val2Max : val2Avr;
                decision[1] = (values[1] >= min2 && values[1] <= max2);
            }
            else
            {
                values[1] = 0;
                decision[1] = true;  // 미사용 시 항상 OK
            }

            // 3번 항목 판정 (Flow/공압 - SPOT 모드에서 선택적)
            if (useFlow)
            {
                values[2] = (type3 == "Maximum" || type3 == "Max") ? val3Max : val3Avr;
                decision[2] = (values[2] >= min3 && values[2] <= max3);
            }
            else
            {
                values[2] = 0;
                decision[2] = true;  // 미사용 시 항상 OK
            }

            string result = "NG";
            if (passOption || (decision[0] && decision[1] && decision[2]))
            {
                result = (passOption) ? "PASS" : "OK";
            }
            else
            {
                result = "NG";
            }

            // 행 추가 - 미사용 항목은 공란으로 표시
            string val1Str = values[0].ToString("0.00");
            string min1Str = min1.ToString("0.00");
            string max1Str = max1.ToString("0.00");

            string val2Str = useVolt ? values[1].ToString("0.00") : "-";
            string min2Str = useVolt ? min2.ToString("0.00") : "-";
            string max2Str = useVolt ? max2.ToString("0.00") : "-";

            string val3Str = useFlow ? values[2].ToString("0.00") : "-";
            string min3Str = useFlow ? min3.ToString("0.00") : "-";
            string max3Str = useFlow ? max3.ToString("0.00") : "-";

            //InitGrid();
            int rowIndex = grid.Rows.Add(
                jigId.ToString(),
                $"{point}//{totalPoint}",
                min1Str, val1Str, max1Str,
                min2Str, val2Str, max2Str,
                min3Str, val3Str, max3Str,
                elapsedTime.ToString("0.0"),
                result
            );

            // 셀 색상 지정 (다크테마: 밝은 파랑/빨강)
            var okColor = System.Drawing.Color.FromArgb(100, 180, 255);   // 밝은 파랑
            var ngColor = System.Drawing.Color.FromArgb(255, 100, 100);   // 밝은 빨강
            grid.Rows[rowIndex].Cells[3].Style.ForeColor = decision[0] ? okColor : ngColor;
            if (useVolt)
                grid.Rows[rowIndex].Cells[6].Style.ForeColor = decision[1] ? okColor : ngColor;
            if (useFlow)
                grid.Rows[rowIndex].Cells[9].Style.ForeColor = decision[2] ? okColor : ngColor;

            // 최종 판정 색상 (조건부: 사용하는 항목만 판정)
            bool allOk = decision[0] && decision[1] && decision[2];
            grid.Rows[rowIndex].Cells[12].Style.ForeColor = allOk ? okColor : ngColor;

            // 마지막 행 보이게
            grid.FirstDisplayedScrollingRowIndex = grid.Rows.Count - 1;
            if (result == "OK" || result == "PASS")
            {
                data.Point_OK[point - 1] = 1;
            }
            else
            {
                data.Point_OK[point - 1] = 0;
            }
        }

        /// <summary>
        /// ioOption 값으로 IO 조건 체크
        /// ioOption 형식: 슬래시 구분 채널 목록 (예: "1/3" → IN[1]=ON, IN[3]=ON 필요)
        /// 지정된 채널만 ON이고, 나머지 채널(1~6)은 OFF여야 매칭
        /// </summary>
        private bool CheckIOCondition(string setting, bool[] IN)
        {
            if (string.IsNullOrWhiteSpace(setting))
                return false;

            // 슬래시로 분리하여 필요한 채널 목록 파싱
            var requiredChannels = new HashSet<int>();
            foreach (var part in setting.Split('/'))
            {
                if (int.TryParse(part.Trim(), out int ch) && ch >= 1 && ch <= 6)
                {
                    requiredChannels.Add(ch);
                }
            }

            if (requiredChannels.Count == 0)
                return false;

            // 채널 1~6 검사: 필요한 채널은 ON, 나머지는 OFF여야 함 (6비트 = 64개)
            for (int ch = 1; ch <= 6; ch++)
            {
                bool shouldBeOn = requiredChannels.Contains(ch);
                bool isOn = IN[ch];

                if (shouldBeOn && !isOn) return false;  // 필요한 채널이 OFF
                if (!shouldBeOn && isOn) return false;  // 불필요한 채널이 ON
            }

            return true;
        }
    }
}

