        private void pictureBox1_Paint(object sender, PaintEventArgs e)
        {
            Graphics g = e.Graphics;

            foreach (var (rect, pointId) in pointRectangles)
            {
                if (rect.Width == 0 || rect.Height == 0)
                    continue;

                System.Drawing.Color fillColor = System.Drawing.Color.Red;
                Brush textBrush = Brushes.White;

                if (pointId - 1 >= 0 && pointId - 1 < data.Point_OK.Length)
                {
                    if (data.Point_OK[pointId - 1] == 1)
                    {
                        fillColor = System.Drawing.Color.Blue;
                        textBrush = Brushes.White;
                    }
                }

                // 내부 채우기 (타원)
                using (Brush fillBrush = new SolidBrush(System.Drawing.Color.FromArgb(120, fillColor)))
                {
                    g.FillEllipse(fillBrush, rect);
                }

                // 테두리 그리기
                using (Pen pen = new Pen(fillColor, 2))
                {
                    g.DrawEllipse(pen, rect);
                }

                // 글자 쓰기
                using (Font font = new Font("Arial", 12, FontStyle.Bold))
                using (StringFormat format = new StringFormat
                {
                    Alignment = StringAlignment.Center,
                    LineAlignment = StringAlignment.Center
                })
                {
                    g.DrawString(pointId.ToString(), font, textBrush, rect, format);
                }
            }
        }

