        private void ShowOnScreenKeyboard()
        {
            if (this.InvokeRequired)
            {
                this.BeginInvoke(new Action(() => ShowOnScreenKeyboard()));
                return;
            }
            try
            {
                // 32비트 앱에서 64비트 osk.exe 실행 (Sysnative 경로 사용)
                string sysNativePath = System.IO.Path.Combine(
                    Environment.GetFolderPath(Environment.SpecialFolder.Windows),
                    "Sysnative", "cmd.exe");

                ProcessStartInfo psi = new ProcessStartInfo();
                psi.FileName = sysNativePath;
                psi.Arguments = "/c start osk.exe";
                psi.WindowStyle = ProcessWindowStyle.Hidden;
                psi.CreateNoWindow = true;
                Process.Start(psi);
            }
            catch (Exception ex)
            {
                //MessageBox.Show("가상 키보드 실행 실패: " + ex.Message);
            }
        }
