        private void ShowFormWithPassword<T>() where T : Form, new()
        {
            if (GlobalValues.strPassWord == "0")
            {
                ShowFormSingleInstance<T>();
            }
            else
            {
                var existingPw = Application.OpenForms.OfType<_FrmPassWord>().FirstOrDefault();
                if (existingPw == null)
                {
                    T targetForm = new T();
                    GlobalValues.openForm = targetForm;

                    _FrmPassWord pwForm = new _FrmPassWord();
                    pwForm.Show();
                }
                else
                {
                    existingPw.BringToFront();
                }
            }
        }

        private void ShowFormSingleInstance<T>() where T : Form, new()
        {
            var existingForm = Application.OpenForms.OfType<T>().FirstOrDefault();
            if (existingForm == null)
            {
                T newForm = new T();
                newForm.Show();
            }
            else
            {
                existingForm.BringToFront();
            }
        }
    }
}

