        private void InitPlots(double valGraphWidth)
        {
            // SPOT 모드: 전류/냉각수온도/공압, CO2 모드: 전류/전압/유량
            string[] yLabels;
            if (GlobalValues.weldMode == "SPOT")
            {
                yLabels = new string[] { "amp(kA)", "temp('C)", "air(kgf)" };
            }
            else
            {
                yLabels = new string[] { "amp(A)", "volt(V)", "flow(L/min)" };
            }
            double[] yMins = { Amp.GraphMin, Volt.GraphMin, Flow.GraphMin };
            double[] yMaxs = { Amp.GraphMax, Volt.GraphMax, Flow.GraphMax };
            double[][] dataBuffers = { ampBuffer, voltBuffer, flowBuffer };

            for (int i = 0; i < formsPlots.Length; i++)
            {
                var plt = formsPlots[i].Plot;
                plt.Clear();

                signalPlots[i] = plt.Add.SignalXY(timeBuffer, dataBuffers[i]);
                signalPlots[i].LineWidth = 2;
                signalPlots[i].Color = new ScottPlot.Color(100, 255, 100); // 밝은 녹색

                signalPlots[i].MaxRenderIndex = 0;

                //plt.Axes.Bottom.Label.Text = "time(s)";
                plt.Axes.Left.Label.Text = yLabels[i];
                plt.Axes.SetLimitsX(0, valGraphWidth);
                plt.Axes.SetLimitsY(yMins[i], yMaxs[i]);

                formsPlots[i].Invoke((MethodInvoker)(() => formsPlots[i].Refresh()));
            }

            bufferIndex = 0;
            sw.Restart();
        }
