        private void btnAutoSet_Click(object sender, EventArgs e)
        {
            if (!_autoSetMode)
            {
                // 비밀번호가 "0"이면 바로 시작
                if (GlobalValues.strPassWord == "0")
                {
                    StartAutoSetMode();
                    btnAutoSet.Text = LanguageManager.Get("btn_autoset_stop");
                    btnAutoSet.BackColor = System.Drawing.Color.Red;
                }
                else
                {
                    // 비밀번호 확인 필요
                    var existingForm = Application.OpenForms.OfType<_FrmPassWord>().FirstOrDefault();
                    if (existingForm == null)
                    {
                        GlobalValues.openForm = null;
                        GlobalValues.pendingAction = () =>
                        {
                            StartAutoSetMode();
                            btnAutoSet.Text = LanguageManager.Get("btn_autoset_stop");
                            btnAutoSet.BackColor = System.Drawing.Color.Red;
                        };

                        _FrmPassWord pwForm = new _FrmPassWord();
                        pwForm.Show();
                    }
                    else
                    {
                        existingForm.BringToFront();
                    }
                }
            }
            else
            {
                // 자동 설정 모드 종료
                StopAutoSetMode();
                btnAutoSet.Text = LanguageManager.Get("btn_autoset");
                btnAutoSet.BackColor = pColor.Theme.buttonColor;
            }
        }

        private void StartAutoSetMode()
        {
            _autoSetMode = true;
            flagStart = false;  // 일반 측정 중지

            // START/STOP 버튼 비활성화
            btnStart.Enabled = false;
            btnStop.Enabled = false;

            // 로그창 표시 (START와 동일)
            panelBtn.Visible = false;
            panelTxtLog.Visible = true;

            // 화면에 자동 설정 모드 표시
            lblAutoSetMode.Text = LanguageManager.Get("lbl_autoset_mode");
            lblAutoSetMode.BackColor = System.Drawing.Color.Red;
            lblAutoSetMode.ForeColor = System.Drawing.Color.Yellow;
            lblAutoSetMode.Visible = true;
            lblAutoSetMode.BringToFront();

            Logger.Log("=== 자동 설정 모드 시작 ===");
            Logger.Log("차종 신호 대기 중...");

            // 자동 설정 스레드 시작
            TrdAutoSet = new Thread(ThreadAutoSet);
            TrdAutoSet.IsBackground = true;
            TrdAutoSet.Start();
        }

        private void StopAutoSetMode()
        {
            _autoSetMode = false;
            lblAutoSetMode.Visible = false;

            // 버튼 패널 복원 (로그창 숨기고 버튼 표시)
            panelBtn.Visible = true;
            panelTxtLog.Visible = false;

            // START/STOP 버튼 다시 활성화
            btnStart.Enabled = true;
            btnStop.Enabled = true;

            if (TrdAutoSet != null && TrdAutoSet.IsAlive)
            {
                TrdAutoSet.Abort();
                TrdAutoSet = null;
            }
            Logger.Log("=== 자동 설정 모드 종료 ===");
        }

        /// <summary>
        /// 자동 설정 스레드
        /// 차종 신호 감지 → 용접 타점 카운트 → 차종 신호 OFF → DB 자동 등록
        /// </summary>
        private void ThreadAutoSet()
        {
            // 클래스 필드 초기화 (중지 시 부분 저장용)
            _autoSetAmpPoints.Clear();
            _autoSetVoltPoints.Clear();
            _autoSetFlowPoints.Clear();
            _autoSetDetectedJigKey = "";
            _autoSetWeldCount = 0;
            bool wasWeldOn = false;
            bool wasJigOn = false;

            List<double> currentAmp = new List<double>();
            List<double> currentVolt = new List<double>();
            List<double> currentFlow = new List<double>();

            while (_autoSetMode)
            {
                try
                {
                    bool isJigOn = false;
                    bool isWeldOn = false;
                    string currentJigKey = "";

                    // Arduino IO 모드: ioOption으로 JIG 감지
                    currentJigKey = GetCurrentIoOption();
                    isJigOn = !string.IsNullOrEmpty(currentJigKey);

                    // 용접 신호
                    if (GlobalValues.weldMode == "SPOT")
                        isWeldOn = Amp.Value > GlobalValues.spotWeldThreshold;
                    else
                        isWeldOn = IO.IN[0];

                    // 차종 신호 ON 감지 (새로운 사이클 시작)
                    if (isJigOn && !wasJigOn)
                    {
                        _autoSetDetectedJigKey = currentJigKey;
                        _autoSetWeldCount = 0;
                        _autoSetAmpPoints.Clear();
                        _autoSetVoltPoints.Clear();
                        _autoSetFlowPoints.Clear();
                        Logger.Log($"[자동설정] 차종 신호 감지: ioOption={_autoSetDetectedJigKey}");

                        // 기존 포인트 삭제
                        DeleteExistingPoints(_autoSetDetectedJigKey);
                    }

                    // 용접 신호 ON (측정 시작)
                    if (isWeldOn && !wasWeldOn && isJigOn)
                    {
                        currentAmp.Clear();
                        currentVolt.Clear();
                        currentFlow.Clear();
                        Logger.Log($"[자동설정] 용접 시작 (포인트 {_autoSetWeldCount + 1})");
                    }

                    // 용접 중 데이터 수집
                    if (isWeldOn && isJigOn)
                    {
                        currentAmp.Add(Amp.Value);
                        currentVolt.Add(Volt.Value);
                        currentFlow.Add(Flow.Value);
                    }

                    // 용접 신호 OFF (측정 완료)
                    if (!isWeldOn && wasWeldOn && isJigOn)
                    {
                        _autoSetWeldCount++;
                        if (currentAmp.Count > 0)
                        {
                            _autoSetAmpPoints.Add(new List<double>(currentAmp));
                            _autoSetVoltPoints.Add(new List<double>(currentVolt));
                            _autoSetFlowPoints.Add(new List<double>(currentFlow));

                            if (GlobalValues.weldMode == "SPOT")
                            {
                                double avgAmp = currentAmp.Average();
                                Logger.Log($"[자동설정] 포인트 {_autoSetWeldCount} 완료 - Amp:{avgAmp:F2}kA (샘플:{currentAmp.Count})");
                            }
                            else
                            {
                                double avgVolt = currentVolt.Average();
                                double avgFlow = currentFlow.Average();
                                Logger.Log($"[자동설정] 포인트 {_autoSetWeldCount} 완료 - Volt:{avgVolt:F1}, Flow:{avgFlow:F1} (샘플:{currentVolt.Count})");
                            }

                            // 포인트 완료 즉시 DB 저장
                            bool saved = AutoRegisterSinglePoint(_autoSetDetectedJigKey, _autoSetWeldCount, currentAmp, currentVolt, currentFlow);
                            if (saved)
                                Logger.Log($"[자동설정] → DB 저장 완료 (Point_{_autoSetWeldCount})");
                            else
                                Logger.Log($"[자동설정] → DB 저장 실패 (Point_{_autoSetWeldCount})");
                        }
                    }

                    // 차종 신호 OFF (사이클 완료)
                    if (!isJigOn && wasJigOn && _autoSetWeldCount > 0)
                    {
                        Logger.Log($"[자동설정] 차종 신호 OFF - 총 {_autoSetWeldCount}개 타점 저장 완료");

                        Logger.Log($"[자동설정] 수동으로 JIG/POINT 버튼을 눌러 확인하세요");
                        Logger.Log("차종 신호 대기 중...");
                        _autoSetWeldCount = 0;
                        _autoSetDetectedJigKey = "";
                        _autoSetAmpPoints.Clear();
                        _autoSetVoltPoints.Clear();
                        _autoSetFlowPoints.Clear();
                    }

                    wasJigOn = isJigOn;
                    wasWeldOn = isWeldOn;

                    Thread.Sleep(10);  // 10ms 주기
                }
                catch (ThreadAbortException)
                {
                    break;
                }
                catch (Exception ex)
                {
                    Logger.Log($"[자동설정] 오류: {ex.Message}");
                }
            }
        }

        /// <summary>
        /// 현재 활성화된 IO 입력 패턴을 ioOption 형식으로 반환
        /// IO.IN[1~6] = 바이너리 차종 신호 (1~64)
        /// </summary>
        private string GetCurrentIoOption()
        {
            // IO.IN[1~6] 중 활성화된 채널 리스트로 반환
            List<int> activeChannels = new List<int>();
            for (int i = 1; i <= 6; i++)
            {
                if (IO.IN[i])
                    activeChannels.Add(i);
            }

            // 0개면 차종 없음
            if (activeChannels.Count == 0) return "";

            return string.Join("/", activeChannels);
        }

        /// <summary>
        /// 자동 측정 데이터를 DB에 등록 (기존 타점 삭제 후 새로 등록)
        /// </summary>
        /// <param name="jigKey">ioOption 값</param>
        /// <param name="pointCount">타점 수</param>
        /// <summary>
        /// 기존 포인트 삭제 (차종 신호 감지 시 실행)
        /// </summary>
        private void DeleteExistingPoints(string jigKey)
        {
            OleDbConnection conn = null;

            try
            {
                conn = new OleDbConnection(GlobalValues.gConString_Part);
                conn.Open();

                // JIG_ID 찾기 (ioOption으로 검색)
                string jigId = null;
                using (var cmd = new OleDbCommand("SELECT Jig_ID FROM Table_Jig WHERE ioOption = ?", conn))
                {
                    cmd.Parameters.AddWithValue("?", jigKey);
                    var result = cmd.ExecuteScalar();
                    if (result != null)
                        jigId = result.ToString();
                }

                if (string.IsNullOrEmpty(jigId))
                {
                    return;
                }

                // 기존 포인트 삭제
                int deletedCount = 0;
                using (var cmd = new OleDbCommand("DELETE FROM Table_Seq WHERE Jig_ID = ?", conn))
                {
                    cmd.Parameters.AddWithValue("?", jigId);
                    deletedCount = cmd.ExecuteNonQuery();
                }
                if (deletedCount > 0)
                    Logger.Log($"[자동설정] 기존 포인트 {deletedCount}개 삭제");
            }
            catch (Exception ex)
            {
                Logger.Log($"[자동설정] 기존 포인트 삭제 오류: {ex.Message}");
            }
            finally
            {
                if (conn != null)
                {
                    conn.Close();
                    conn.Dispose();
                }
            }
        }

        /// <summary>
        /// 단일 포인트를 즉시 DB에 저장 (실시간 저장)
        /// </summary>
        private bool AutoRegisterSinglePoint(string jigKey, int pointId,
            List<double> ampData, List<double> voltData, List<double> flowData)
        {
            OleDbConnection conn = null;

            try
            {
                conn = new OleDbConnection(GlobalValues.gConString_Part);
                conn.Open();

                // JIG_ID 찾기 (ioOption으로 검색)
                string jigId = null;
                using (var cmd = new OleDbCommand("SELECT Jig_ID FROM Table_Jig WHERE ioOption = ?", conn))
                {
                    cmd.Parameters.AddWithValue("?", jigKey);
                    var result = cmd.ExecuteScalar();
                    if (result != null)
                        jigId = result.ToString();
                }

                if (string.IsNullOrEmpty(jigId))
                {
                    return false;
                }

                // 데이터 유효성 검사
                if (ampData == null || ampData.Count == 0 ||
                    voltData == null || voltData.Count == 0 ||
                    flowData == null || flowData.Count == 0)
                {
                    return false;
                }

                // SPOT 모드 여부 확인
                bool isSpotMode = GlobalValues.weldMode == "SPOT";

                // SPOT 모드: 전부 Max 값 사용, CO2 모드: Amp/Volt는 Average, Flow만 Max
                double baseAmp, baseVolt, baseFlow;
                string ampVoltType;
                if (isSpotMode)
                {
                    baseAmp = Math.Round(ampData.Max(), 2);
                    baseVolt = Math.Round(voltData.Max(), 2);
                    baseFlow = Math.Round(flowData.Max(), 2);
                    ampVoltType = "Max";
                }
                else
                {
                    baseAmp = Math.Round(ampData.Average(), 2);
                    baseVolt = Math.Round(voltData.Average(), 2);
                    baseFlow = Math.Round(flowData.Max(), 2);  // Flow만 Max
                    ampVoltType = "Average";
                }

                // NaN/Infinity 체크
                if (double.IsNaN(baseAmp) || double.IsInfinity(baseAmp) ||
                    double.IsNaN(baseVolt) || double.IsInfinity(baseVolt) ||
                    double.IsNaN(baseFlow) || double.IsInfinity(baseFlow))
                {
                    return false;
                }

                // ±30% 스펙 계산
                double ampMin = Math.Round(baseAmp * 0.7, 2);
                double ampMax = Math.Round(baseAmp * 1.3, 2);
                double voltMin = Math.Round(baseVolt * 0.7, 2);
                double voltMax = Math.Round(baseVolt * 1.3, 2);
                double flowMin = Math.Round(baseFlow * 0.7, 2);
                double flowMax = Math.Round(baseFlow * 1.3, 2);

                // INSERT (트랜잭션 없이 즉시 커밋)
                using (var cmd = new OleDbCommand(@"
                    INSERT INTO Table_Seq
                    (Jig_ID, Point_ID, Value1_Max, Value1_Min, Value2_Max, Value2_Min, Value3_Max, Value3_Min,
                     Value1_Tol, Value2_Tol, Value3_Tol, Value1_Type, Value2_Type, Value3_Type,
                     StartSector, EndSector, Pass, Image_Coord_X, Image_Coord_Y, Image_Size_X, Image_Size_Y, graphWidth)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)", conn))
                {
                    cmd.Parameters.AddWithValue("?", jigId);
                    cmd.Parameters.AddWithValue("?", pointId.ToString());
                    cmd.Parameters.AddWithValue("?", ampMax);
                    cmd.Parameters.AddWithValue("?", ampMin);
                    cmd.Parameters.AddWithValue("?", voltMax);
                    cmd.Parameters.AddWithValue("?", voltMin);
                    cmd.Parameters.AddWithValue("?", flowMax);
                    cmd.Parameters.AddWithValue("?", flowMin);
                    cmd.Parameters.AddWithValue("?", 1);  // Value1_Tol (Offset=1)
                    cmd.Parameters.AddWithValue("?", 1);  // Value2_Tol (Offset=1)
                    cmd.Parameters.AddWithValue("?", 1);  // Value3_Tol (Offset=1)
                    cmd.Parameters.AddWithValue("?", ampVoltType);  // Value1_Type (Amp)
                    cmd.Parameters.AddWithValue("?", ampVoltType);  // Value2_Type (Volt)
                    cmd.Parameters.AddWithValue("?", "Max");         // Value3_Type (Flow) - 항상 Max
                    cmd.Parameters.AddWithValue("?", isSpotMode ? 0 : 5);  // StartSector (SPOT: 0%, CO2: 5% trim)
                    cmd.Parameters.AddWithValue("?", isSpotMode ? 0 : 5);  // EndSector (SPOT: 0%, CO2: 5% trim)
                    cmd.Parameters.AddWithValue("?", 0);   // Pass (false)
                    cmd.Parameters.AddWithValue("?", 0);   // Image_Coord_X
                    cmd.Parameters.AddWithValue("?", 0);   // Image_Coord_Y
                    cmd.Parameters.AddWithValue("?", 50);  // Image_Size_X
                    cmd.Parameters.AddWithValue("?", 50);  // Image_Size_Y
                    cmd.Parameters.AddWithValue("?", 10);  // graphWidth
                    cmd.ExecuteNonQuery();
                }

                return true;
            }
            catch (Exception ex)
            {
                Logger.Log($"[자동설정] Point {pointId} 저장 오류: {ex.Message}");
                return false;
            }
            finally
            {
                if (conn != null)
                {
                    conn.Close();
                    conn.Dispose();
                }
            }
        }

        /// <param name="ampData">Amp 측정 데이터</param>
        /// <param name="voltData">Volt 측정 데이터</param>
        /// <param name="flowData">Flow 측정 데이터</param>
        private bool AutoRegisterToDb(string jigKey, int pointCount,
            List<List<double>> ampData, List<List<double>> voltData, List<List<double>> flowData)
        {
            OleDbConnection conn = null;
            OleDbTransaction transaction = null;

            try
            {
                conn = new OleDbConnection(GlobalValues.gConString_Part);
                conn.Open();

                // 트랜잭션 시작
                transaction = conn.BeginTransaction();

                // JIG_ID 찾기: ioOption으로 검색
                string jigId = null;
                using (var cmd = new OleDbCommand("SELECT Jig_ID FROM Table_Jig WHERE ioOption = ?", conn, transaction))
                {
                    cmd.Parameters.AddWithValue("?", jigKey);
                    var result = cmd.ExecuteScalar();
                    if (result != null)
                        jigId = result.ToString();
                }

                if (string.IsNullOrEmpty(jigId))
                {
                    Logger.Log($"[자동설정] ioOption={jigKey}에 해당하는 JIG를 찾을 수 없음");

                    transaction.Rollback();
                    return false;
                }

                Logger.Log($"[자동설정] 기존 JIG 사용: Jig_ID={jigId}");

                // 데이터 개수 일치 확인 (방어 코드)
                if (ampData.Count != pointCount || voltData.Count != pointCount || flowData.Count != pointCount)
                {
                    Logger.Log($"[자동설정] 데이터 개수 불일치 - Amp:{ampData.Count}, Volt:{voltData.Count}, Flow:{flowData.Count}, Count:{pointCount}");
                    transaction.Rollback();
                    return false;
                }

                // 기존 포인트 삭제
                int deletedCount = 0;
                using (var cmd = new OleDbCommand("DELETE FROM Table_Seq WHERE Jig_ID = ?", conn, transaction))
                {
                    cmd.Parameters.AddWithValue("?", jigId);
                    deletedCount = cmd.ExecuteNonQuery();
                }
                if (deletedCount > 0)
                    Logger.Log($"[자동설정] 기존 포인트 {deletedCount}개 삭제");

                // DELETE 트랜잭션 커밋 (INSERT는 개별 저장)
                transaction.Commit();
                transaction.Dispose();
                transaction = null;
                Logger.Log($"[자동설정] 기존 포인트 삭제 완료");

                // Point_ID는 1부터 시작
                int maxPointId = 0;

                Logger.Log($"[자동설정] 신규 등록 시작: {pointCount}개 (개별 저장)");

                // SPOT 모드 여부 확인
                bool isSpotMode = GlobalValues.weldMode == "SPOT";

                // Table_Seq에 새 포인트 추가
                for (int i = 0; i < pointCount; i++)
                {
                    try
                    {
                        // 매 포인트마다 진행률 출력
                        Logger.Log($"[자동설정] 등록 진행: {i + 1}/{pointCount}");

                        int newPointId = maxPointId + i + 1;

                        // 배열 범위 체크 (방어 코드)
                        if (i >= ampData.Count || i >= voltData.Count || i >= flowData.Count)
                        {
                            Logger.Log($"[자동설정] Point {newPointId}: 인덱스 초과 - 건너뜀");
                            continue;
                        }

                        // 데이터 유효성 검사
                        if (ampData[i] == null || ampData[i].Count == 0 ||
                            voltData[i] == null || voltData[i].Count == 0 ||
                            flowData[i] == null || flowData[i].Count == 0)
                        {
                            Logger.Log($"[자동설정] Point {newPointId}: 데이터 없음 - 건너뜀");
                            continue;
                        }

                        // SPOT 모드: 전부 Max 값 사용
                        // CO2 모드: Amp/Volt는 Average, Flow만 Max
                        double baseAmp, baseVolt, baseFlow;
                        string ampVoltType;
                        if (isSpotMode)
                        {
                            baseAmp = Math.Round(ampData[i].Max(), 2);
                            baseVolt = Math.Round(voltData[i].Max(), 2);
                            baseFlow = Math.Round(flowData[i].Max(), 2);
                            ampVoltType = "Max";
                        }
                        else
                        {
                            baseAmp = Math.Round(ampData[i].Average(), 2);
                            baseVolt = Math.Round(voltData[i].Average(), 2);
                            baseFlow = Math.Round(flowData[i].Max(), 2);  // Flow만 Max
                            ampVoltType = "Average";
                        }

                        // NaN/Infinity 체크
                        if (double.IsNaN(baseAmp) || double.IsInfinity(baseAmp) ||
                            double.IsNaN(baseVolt) || double.IsInfinity(baseVolt) ||
                            double.IsNaN(baseFlow) || double.IsInfinity(baseFlow))
                        {
                            Logger.Log($"[자동설정] Point {newPointId}: 잘못된 값 (Amp:{baseAmp}, Volt:{baseVolt}, Flow:{baseFlow}) - 건너뜀");
                            continue;
                        }

                        // ±30% 스펙 계산
                        double ampMin = Math.Round(baseAmp * 0.7, 2);
                        double ampMax = Math.Round(baseAmp * 1.3, 2);
                        double voltMin = Math.Round(baseVolt * 0.7, 2);
                        double voltMax = Math.Round(baseVolt * 1.3, 2);
                        double flowMin = Math.Round(baseFlow * 0.7, 2);
                        double flowMax = Math.Round(baseFlow * 1.3, 2);

                        using (var cmd = new OleDbCommand(@"
                            INSERT INTO Table_Seq
                            (Jig_ID, Point_ID, Value1_Max, Value1_Min, Value2_Max, Value2_Min, Value3_Max, Value3_Min,
                             Value1_Tol, Value2_Tol, Value3_Tol, Value1_Type, Value2_Type, Value3_Type,
                             StartSector, EndSector, Pass, Image_Coord_X, Image_Coord_Y, Image_Size_X, Image_Size_Y, graphWidth)
                            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)", conn))
                        {
                            cmd.Parameters.AddWithValue("?", jigId);
                            cmd.Parameters.AddWithValue("?", newPointId.ToString());
                            cmd.Parameters.AddWithValue("?", ampMax);
                            cmd.Parameters.AddWithValue("?", ampMin);
                            cmd.Parameters.AddWithValue("?", voltMax);
                            cmd.Parameters.AddWithValue("?", voltMin);
                            cmd.Parameters.AddWithValue("?", flowMax);
                            cmd.Parameters.AddWithValue("?", flowMin);
                            cmd.Parameters.AddWithValue("?", 1);  // Value1_Tol (Offset=1)
                            cmd.Parameters.AddWithValue("?", 1);  // Value2_Tol (Offset=1)
                            cmd.Parameters.AddWithValue("?", 1);  // Value3_Tol (Offset=1)
                            cmd.Parameters.AddWithValue("?", ampVoltType);  // Value1_Type (Amp)
                            cmd.Parameters.AddWithValue("?", ampVoltType);  // Value2_Type (Volt)
                            cmd.Parameters.AddWithValue("?", "Max");         // Value3_Type (Flow) - 항상 Max
                            cmd.Parameters.AddWithValue("?", isSpotMode ? 0 : 5);  // StartSector (SPOT: 0%, CO2: 5% trim)
                            cmd.Parameters.AddWithValue("?", isSpotMode ? 0 : 5);  // EndSector (SPOT: 0%, CO2: 5% trim)
                            cmd.Parameters.AddWithValue("?", 0);   // Pass (false)
                            cmd.Parameters.AddWithValue("?", 0);   // Image_Coord_X
                            cmd.Parameters.AddWithValue("?", 0);   // Image_Coord_Y
                            cmd.Parameters.AddWithValue("?", 50);  // Image_Size_X
                            cmd.Parameters.AddWithValue("?", 50);  // Image_Size_Y
                            cmd.Parameters.AddWithValue("?", 10);  // graphWidth
                            cmd.ExecuteNonQuery();
                        }

                        // UI 응답성 확보를 위한 짧은 대기
                        Thread.Sleep(10);
                    }
                    catch (Exception ex)
                    {
                        Logger.Log($"[자동설정] Point {i + 1} 등록 오류: {ex.Message}");
                        Logger.Log($"[자동설정] StackTrace: {ex.StackTrace}");
                        // 이 포인트는 건너뛰고 계속 진행
                    }
                }

                Logger.Log($"[자동설정] INSERT 완료: {pointCount}개");

                return true;
            }
            catch (Exception ex)
            {
                Logger.Log($"[자동설정] DB 오류: {ex.Message}");
                Logger.Log($"[자동설정] StackTrace: {ex.StackTrace}");

                try
                {
                    if (transaction != null)
                    {
                        transaction.Rollback();
                        Logger.Log($"[자동설정] 트랜잭션 롤백 완료");
                    }
                }
                catch (Exception rollbackEx)
                {
                    Logger.Log($"[자동설정] 롤백 오류: {rollbackEx.Message}");
                }

                return false;
            }
            finally
            {
                if (transaction != null)
                {
                    transaction.Dispose();
                }
                if (conn != null)
                {
                    conn.Close();
                    conn.Dispose();
                }
            }
        }

        /// <summary>
        /// 다음 자동 Jig_ID 생성 (AUTO_001, AUTO_002, ...)
        /// </summary>
        private string GetNextAutoJigId(OleDbConnection conn)
        {
            int maxNum = 0;
            using (var cmd = new OleDbCommand("SELECT Jig_ID FROM Table_Jig WHERE Jig_ID LIKE 'AUTO_%'", conn))
            {
                using (var reader = cmd.ExecuteReader())
                {
                    while (reader.Read())
                    {
                        string jigId = reader["Jig_ID"].ToString();
                        if (jigId.StartsWith("AUTO_") && int.TryParse(jigId.Substring(5), out int num))
                        {
                            if (num > maxNum) maxNum = num;
                        }
                    }
                }
            }
            return $"AUTO_{(maxNum + 1):D3}";
        }

        /// <summary>
        /// labelDecision 클릭 - 테스트 저장
        /// </summary>
        private void labelDecision_Click(object sender, EventArgs e)
        {
            var rnd = new Random();
            var amp = new List<List<double>>();
            var volt = new List<List<double>>();
            var flow = new List<List<double>>();

            for (int i = 0; i < 10; i++)
            {
                amp.Add(new List<double> { 100 + rnd.NextDouble() * 100 });
                volt.Add(new List<double> { 20 + rnd.NextDouble() * 20 });
                flow.Add(new List<double> { 10 + rnd.NextDouble() * 10 });
            }

            // Jig_ID="1"로 직접 저장 (테스트용)
            AutoRegisterToDbDirect("1", 10, amp, volt, flow);
            LoadAllPointData();
            LoadJigData();
            Logger.Log("[테스트] 저장 완료");
        }

        /// <summary>
        /// 테스트용 - Jig_ID로 직접 DB 저장
        /// </summary>
        private bool AutoRegisterToDbDirect(string jigId, int pointCount,
            List<List<double>> ampData, List<List<double>> voltData, List<List<double>> flowData)
        {
            try
            {
                using (var conn = new OleDbConnection(GlobalValues.gConString_Part))
                {
                    conn.Open();

                    // 기존 포인트 삭제
                    using (var cmd = new OleDbCommand("DELETE FROM Table_Seq WHERE Jig_ID = ?", conn))
                    {
                        cmd.Parameters.AddWithValue("?", jigId);
                        cmd.ExecuteNonQuery();
                    }

                    bool isSpotMode = GlobalValues.weldMode == "SPOT";

                    for (int i = 0; i < pointCount; i++)
                    {
                        int newPointId = i + 1;

                        if (ampData[i] == null || ampData[i].Count == 0) continue;

                        double baseAmp = isSpotMode ? ampData[i].Max() : ampData[i].Average();
                        double baseVolt = isSpotMode ? voltData[i].Max() : voltData[i].Average();
                        double baseFlow = flowData[i].Max();

                        using (var cmd = new OleDbCommand(@"
                            INSERT INTO Table_Seq
                            (Jig_ID, Point_ID, Value1_Max, Value1_Min, Value2_Max, Value2_Min, Value3_Max, Value3_Min,
                             Value1_Tol, Value2_Tol, Value3_Tol, Value1_Type, Value2_Type, Value3_Type,
                             StartSector, EndSector, Pass, Image_Coord_X, Image_Coord_Y, Image_Size_X, Image_Size_Y, graphWidth)
                            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)", conn))
                        {
                            cmd.Parameters.AddWithValue("?", jigId);
                            cmd.Parameters.AddWithValue("?", newPointId.ToString());
                            cmd.Parameters.AddWithValue("?", Math.Round(baseAmp * 1.3, 2));
                            cmd.Parameters.AddWithValue("?", Math.Round(baseAmp * 0.7, 2));
                            cmd.Parameters.AddWithValue("?", Math.Round(baseVolt * 1.3, 2));
                            cmd.Parameters.AddWithValue("?", Math.Round(baseVolt * 0.7, 2));
                            cmd.Parameters.AddWithValue("?", Math.Round(baseFlow * 1.3, 2));
                            cmd.Parameters.AddWithValue("?", Math.Round(baseFlow * 0.7, 2));
                            cmd.Parameters.AddWithValue("?", 1);
                            cmd.Parameters.AddWithValue("?", 1);
                            cmd.Parameters.AddWithValue("?", 1);
                            cmd.Parameters.AddWithValue("?", isSpotMode ? "Max" : "Average");
                            cmd.Parameters.AddWithValue("?", isSpotMode ? "Max" : "Average");
                            cmd.Parameters.AddWithValue("?", "Max");
                            cmd.Parameters.AddWithValue("?", isSpotMode ? 0 : 5);  // StartSector (SPOT: 0%, CO2: 5% trim)
                            cmd.Parameters.AddWithValue("?", isSpotMode ? 0 : 5);  // EndSector (SPOT: 0%, CO2: 5% trim)
                            cmd.Parameters.AddWithValue("?", 1);
                            cmd.Parameters.AddWithValue("?", 0);
                            cmd.Parameters.AddWithValue("?", 0);
                            cmd.Parameters.AddWithValue("?", 0);
                            cmd.Parameters.AddWithValue("?", 0);
                            cmd.Parameters.AddWithValue("?", 100);
                            cmd.ExecuteNonQuery();
                        }
                    }
                    Logger.Log($"[테스트] Jig_ID={jigId}에 {pointCount}개 포인트 저장됨");
                    return true;
                }
            }
            catch (Exception ex)
            {
                Logger.Log($"[테스트] 저장 오류: {ex.Message}");
                return false;
            }
        }

        /// <summary>
        /// JIG 1~128번까지 자동 초기화
        /// </summary>
        private void InitializeJig31()
        {
            try
            {
                using (var conn = new OleDbConnection(GlobalValues.gConString_Part))
                {
                    conn.Open();

                    // 기존 JIG ID 목록 가져오기
                    var existingJigIds = new HashSet<string>();
                    using (var cmd = new OleDbCommand("SELECT Jig_ID FROM Table_Jig", conn))
                    using (var reader = cmd.ExecuteReader())
                    {
                        while (reader.Read())
                        {
                            existingJigIds.Add(reader["Jig_ID"].ToString());
                        }
                    }

                    // 1~128번 중 없는 JIG만 추가 (기존 데이터 보존)
                    int addedCount = 0;
                    for (int jigNum = 1; jigNum <= 128; jigNum++)
                    {
                        string jigId = jigNum.ToString();  // "1", "2", ... "128"

                        if (existingJigIds.Contains(jigId))
                            continue;  // 이미 있으면 스킵 (기존 데이터 보존)

                        string ioOption;
                        if (jigNum <= 64)
                        {
                            var channels = new List<string>();
                            for (int bit = 0; bit < 6; bit++)
                                if ((jigNum & (1 << bit)) != 0) channels.Add((bit + 1).ToString());
                            ioOption = string.Join("/", channels);
                        }
                        else
                            ioOption = "";  // 65~128: 미사용

                        using (var insertCmd = new OleDbCommand(
                            "INSERT INTO Table_Jig (Jig_ID, PartNo, PartName, ioOption) VALUES (?, ?, ?, ?)", conn))
                        {
                            insertCmd.Parameters.AddWithValue("?", jigId);
                            insertCmd.Parameters.AddWithValue("?", "-");
                            insertCmd.Parameters.AddWithValue("?", "-");
                            insertCmd.Parameters.AddWithValue("?", ioOption);
                            insertCmd.ExecuteNonQuery();
                            addedCount++;
                        }
                    }

                    if (addedCount > 0)
                        System.Diagnostics.Debug.WriteLine($"JIG {addedCount}개 추가 (기존 데이터 보존)");
                }
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"JIG 초기화 오류: {ex.Message}");
            }
        }

        /// <summary>
        /// 숫자를 ioOption 형식으로 변환 (5비트 바이너리)
        /// 예: 1→"1", 3→"1/2", 16→"5", 31→"1/2/3/4/5"
        /// </summary>
        private string GetIoOptionFromNumber(int num)
        {
            List<int> bits = new List<int>();
            for (int i = 0; i < 5; i++)
            {
                if ((num & (1 << i)) != 0)
                    bits.Add(i + 1);  // 1-based (IO.IN[1]~IO.IN[5])
            }
            return string.Join("/", bits);
        }

