        private Thread Trd1;
        private Thread Trd2;
        private Thread TrdAutoSet;  // 자동 설정 스레드
        private bool _autoSetMode = false;  // 자동 설정 모드

        // 자동 설정 데이터 (중지 시 부분 저장용)
        private List<List<double>> _autoSetAmpPoints = new List<List<double>>();
        private List<List<double>> _autoSetVoltPoints = new List<List<double>>();
        private List<List<double>> _autoSetFlowPoints = new List<List<double>>();
        private string _autoSetDetectedJigKey = "";
        private int _autoSetWeldCount = 0;
        private int _debugLogTimer = 0;  // 디버깅 로그 타이머
        private int _jigOffDebounceCount = 0;  // JIG OFF 디바운싱 카운터
        private int _jigOnDebounceCount = 0;  // JIG ON 디바운싱 카운터
        private const int JIG_DEBOUNCE_THRESHOLD = 10;  // 10회 연속 (약 50ms)
        private static Button[] btnIn = new Button[8];
        private static Button[] btnOut = new Button[8];
        private System.IO.Ports.SerialPort SerialAduino = new SerialPort();
        private List<SerialPort> SerialScanners = new List<SerialPort>();  // 복수 스캐너 포트
        private List<SerialPort> SerialPrinters = new List<SerialPort>();  // 복수 프린터 포트
        private StringBuilder DoutString = new StringBuilder("S00000000E");
        private StringBuilder RecvString = new StringBuilder();
        private ScottPlot.WinForms.FormsPlot[] formsPlots;
        private dynamic[] signalPlots;  // 0: Amp, 1: Volt, 2: Flow
        private double[] timeBuffer = new double[50000];
        private double[] ampBuffer = new double[50000];
        private double[] voltBuffer = new double[50000];
        private double[] flowBuffer = new double[50000];
        private int bufferIndex = 0;
        private Stopwatch sw = new Stopwatch();
        private System.Windows.Forms.Timer startTimer;

        private bool flagStart = false;
        private FilteredValue AmpFilter;
        private FilteredValue VoltFilter;
        private FilteredValue FlowFilter;
        private static Mutex mutex;

        private enum WorkState
        {
            Idle = 0,
            JigSignalCompleted,
            LoadModelCompleted,
            WeldSignalCompleted,
            WaitForMeasureSignalOn,
            WaitForMeasureDelay,
            Measuring,
            WaitForMeasureSignalOff,
