        private class RawPointData
        {
            public int Point;
            public List<double> Time = new List<double>();
            public List<double> Amp = new List<double>();
            public List<double> Volt = new List<double>();
            public List<double> Flow = new List<double>();
            // 결과값
            public double AmpAvg, AmpMax, AmpMin;
            public double VoltAvg, VoltMax, VoltMin;
            public double FlowAvg, FlowMax, FlowMin;
            public double Elapsed;
            public string Result;
        }
        private List<RawPointData> rawDataList = new List<RawPointData>();
        private string rawDataTimestamp; // 저장 파일명용 타임스탬프

        private void BtnOut_Click(object sender, EventArgs e)
        {
            if (sender is Button btn && btn.Tag is int index)
            {
                if (btnOut[index].BackColor == pColor.Theme.DeepGreen)
                {
                    DoOn(index);
                    // 실제 IO 신호 ON 로직 추가
                }
                else
                {
                    DoOff(index);
                    // 실제 IO 신호 OFF 로직 추가
                }
                //MessageBox.Show($"btnOut{index:D2} 클릭됨");
            }
        }
        public _FrmMain()
        {
            InitializeComponent();

            // 다크테마 적용
            ThemeManager.ApplyDarkTheme(this);

            // Designer.cs에서 명시적으로 설정된 색상 덮어쓰기
            labelDecision.BackColor = ThemeManager.DarkTheme.BackgroundLight;
            srcTxtLog.BackColor = ThemeManager.DarkTheme.BackgroundLight;
            srcTxtLog.ForeColor = ThemeManager.DarkTheme.TextPrimary;

            bool isNewInstance;
            mutex = new Mutex(true, "FtechTestUI", out isNewInstance);
            if (!isNewInstance)
            {
                MessageBox.Show(LanguageManager.Get("msg_already_running"), LanguageManager.Get("msg_prevent_duplicate"), MessageBoxButtons.OK, MessageBoxIcon.Warning);
                Environment.Exit(0); // 완전히 종료
            }

            this.pictureBox1.Paint += pictureBox1_Paint;

            Logger.Initialize(srcTxtLog);

            for (int i = 0; i < 8; i++)
            {
                string btnName = $"btnIn{i:D2}";
                btnIn[i] = this.Controls.Find(btnName, true).FirstOrDefault() as Button;

                btnName = $"btnOut{i:D2}";
                btnOut[i] = this.Controls.Find(btnName, true).FirstOrDefault() as Button;

                if (btnOut[i] != null)
                {
                    btnOut[i].Tag = i; // 인덱스를 Tag에 저장
                    btnOut[i].Click += BtnOut_Click;
                }

                DoOff(i);
            }

            formsPlots = new ScottPlot.WinForms.FormsPlot[] { formsPlot1, formsPlot2, formsPlot3 };
            signalPlots = new dynamic[3];

            // 그래프에 다크테마 적용
            foreach (var plot in formsPlots)
            {
                ThemeManager.ApplyDarkThemeToPlot(plot);
            }

            StyleControls();
            panelBtn.Visible = true;
            panelTxtLog.Visible = false;

            GlobalValues.LoadSettingsFromIni();

            // 1~128번 JIG 강제 초기화
            InitializeJig31();

            // 언어 설정 적용
            ApplyLanguage();

            // 이미지 기능 레이아웃 적용
            ApplyImageFeatureLayout();

            AmpFilter = new FilteredValue(GlobalValues.alpha);
            VoltFilter = new FilteredValue(GlobalValues.alpha);
            FlowFilter = new FilteredValue(GlobalValues.alpha);

            PortOpen(SerialAduino, GlobalValues.aduinoPort, 115200, "SerialAduino");

            // 스캐너/프린터 포트 오픈
            OpenScannerPorts();
            OpenPrinterPorts();

            if (SerialAduino.IsOpen)
            {
                SerialAduino.Write(DoutString.ToString());
                Trd1 = new Thread(ThreadTask1);
                Trd1.IsBackground = true;
                Trd1.Start();
                Logger.Log("Aduino Thread Start");
            }

            Trd2 = new Thread(ThreadTask2);
            Trd2.IsBackground = true;
            Trd2.Start();

            InitControl();

            startTimer = new System.Windows.Forms.Timer();
            startTimer.Interval = 1000; // 1000ms 간격 체크
            startTimer.Tick += startTimer_Tick;
            startTimer.Start();

        }
        private void startTimer_Tick(object sender, EventArgs e)
        {
            InitControl();
            GlobalValues.LoadSettingsFromIni();
            AmpFilter = new FilteredValue(GlobalValues.alpha);
            VoltFilter = new FilteredValue(GlobalValues.alpha);
            FlowFilter = new FilteredValue(GlobalValues.alpha);
            panelBtn.Visible = false;
            panelTxtLog.Visible = true;
            flagStart = true;
            Logger.Log("START");
            LoadAllPointData();
            LoadJigData();
            startTimer.Stop();
        }
    }
}

