115→        /// <summary>
116→        /// 점검항목 파일에서 로드 (없으면 기본값 사용)
117→        /// </summary>
118→        private void LoadItems()
119→        {
120→            _items.Clear();
121→            string filePath = GetItemsFilePath();
122→
123→            if (File.Exists(filePath))
124→            {
125→                try
126→                {
127→                    foreach (var line in File.ReadAllLines(filePath, System.Text.Encoding.UTF8))
128→                    {
129→                        string trimmed = line.Trim();
130→                        if (string.IsNullOrEmpty(trimmed) || trimmed.StartsWith("#")) continue;
131→
132→                        // 탭 구분: 점검항목\t점검기준\t점검방법\t구분
133→                        string[] parts = trimmed.Split('\t');
134→                        if (parts.Length >= 4)
135→                        {
136→                            _items.Add(new[] { parts[0], parts[1], parts[2], parts[3] });
137→                        }
138→                    }
139→                }
140→                catch (Exception ex)
141→                {
142→                    Logger.Error($"[일상점검] 항목 로드 실패: {ex.Message}");
143→                }
144→            }
145→
146→            // 파일 없거나 비어있으면 기본값
147→            if (_items.Count == 0)
148→            {
149→                foreach (var item in DEFAULT_ITEMS)
150→                    _items.Add((string[])item.Clone());
151→                SaveItems();
152→            }
153→        }
