156→        /// 점검항목 파일에 저장
157→        /// </summary>
158→        private void SaveItems()
159→        {
160→            try
161→            {
162→                if (!Directory.Exists(_basePath))
163→                    Directory.CreateDirectory(_basePath);
164→
165→                string filePath = GetItemsFilePath();
166→                using (var sw = new StreamWriter(filePath, false, System.Text.Encoding.UTF8))
167→                {
168→                    sw.WriteLine("# 점검항목 설정 (탭 구분: 점검항목\\t점검기준\\t점검방법\\t구분)");
169→                    sw.WriteLine("# 이 파일을 직접 수정하거나 프로그램에서 추가/삭제/편집 가능");
170→                    foreach (var item in _items)
171→                    {
172→                        sw.WriteLine($"{item[0]}\t{item[1]}\t{item[2]}\t{item[3]}");
173→                    }
174→                }
175→            }
176→            catch (Exception ex)
177→            {
178→                Logger.Error($"[일상점검] 항목 저장 실패: {ex.Message}");
179→            }
180→        }
