371→        private void Dgv_CellClick(object sender, DataGridViewCellEventArgs e)
372→        {
373→            if (_loading || e.RowIndex < 0 || e.ColumnIndex < 5) return;
374→
375→            int day = e.ColumnIndex - 4; // colDay1 = index 5
376→            if (day < 1 || day > 31) return;
377→
378→            int daysInMonth = DateTime.DaysInMonth(_currentMonth.Year, _currentMonth.Month);
379→            if (day > daysInMonth) return;
380→
381→            var cell = dgv.Rows[e.RowIndex].Cells[e.ColumnIndex];
382→            string current = cell.Value?.ToString()?.Trim() ?? "";
383→
384→            // 순환: "" → O → X → ""
385→            string next;
386→            if (current == "") next = "O";
387→            else if (current == "O") next = "X";
388→            else next = "";
389→
390→            cell.Value = next;
391→            ApplyCellColor(cell, next);
392→
393→            // 체크 로그 기록
394→            string itemName = dgv.Rows[e.RowIndex].Cells["colItem"].Value?.ToString() ?? "";
395→            LogCheckAction(e.RowIndex + 1, itemName, day, current, next);
396→
397→            // 자동 저장
398→            SaveData();
399→        }
