580→                txtSupervisor.Text = "설비관리담당자";
581→                txtEquipName.Text = "";
582→                txtQuality.Text = "19기";
583→                txtEquipNo.Text = "IM-000-RW-01-32";
584→                _loading = false;
585→                return;
586→            }
587→
588→            try
589→            {
590→                string currentSection = "";
591→                foreach (var line in File.ReadAllLines(filePath, System.Text.Encoding.UTF8))
592→                {
593→                    string trimmed = line.Trim();
594→                    if (string.IsNullOrEmpty(trimmed)) continue;
595→
596→                    if (trimmed.StartsWith("[") && trimmed.EndsWith("]"))
597→                    {
598→                        currentSection = trimmed.Substring(1, trimmed.Length - 2);
599→                        continue;
600→                    }
601→
602→                    int eqIdx = trimmed.IndexOf('=');
603→                    if (eqIdx < 0) continue;
604→                    string key = trimmed.Substring(0, eqIdx);
605→                    string val = trimmed.Substring(eqIdx + 1);
606→
607→                    if (currentSection == "Header")
608→                    {
609→                        switch (key)
610→                        {
611→                            case "Dept": txtDept.Text = val; break;
612→                            case "Supervisor": txtSupervisor.Text = val; break;
613→                            case "EquipName": txtEquipName.Text = val; break;
614→                            case "Quality": txtQuality.Text = val; break;
615→                            case "EquipNo": txtEquipNo.Text = val; break;
616→                            case "Writer": txtWriter.Text = val; break;
617→                            case "Reviewer": txtReviewer.Text = val; break;
618→                            case "Approver": txtApprover.Text = val; break;
619→                            case "ProdSign": txtProdSign.Text = val; break;
620→                            case "QualSign": txtQualSign.Text = val; break;
621→                        }
622→                    }
623→                    else if (currentSection.StartsWith("Item"))
624→                    {
625→                        int itemNo;
626→                        if (!int.TryParse(currentSection.Substring(4), out itemNo)) continue;
627→                        if (itemNo < 1 || itemNo > dgv.Rows.Count) continue;
628→
629→                        if (key.StartsWith("Day"))
630→                        {
631→                            int dayNo;
632→                            if (!int.TryParse(key.Substring(3), out dayNo)) continue;
633→                            if (dayNo < 1 || dayNo > 31) continue;
634→
635→                            string colName = $"colDay{dayNo}";
636→                            var cell = dgv.Rows[itemNo - 1].Cells[colName];
637→                            cell.Value = val;
638→                            ApplyCellColor(cell, val);
639→                        }
640→                    }
641→                }
642→            }
643→            catch (Exception ex)
644→            {
645→                Logger.Error($"[일상점검] 로드 실패: {ex.Message}");
646→            }
647→
648→            _loading = false;
649→        }
650→
651→        #endregion
652→
653→        #region 체크 로그 기록
654→
655→        /// <summary>
656→        /// 체크 변경 시 타임스탬프 로그 기록
657→        /// </summary>
658→        private void LogCheckAction(int itemNo, string itemName, int day, string oldVal, string newVal)
659→        {
660→            try
661→            {
662→                string logPath = GetLogFilePath();
663→                string timestamp = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");
664→                string oldDisplay = string.IsNullOrEmpty(oldVal) ? "-" : oldVal;
665→                string newDisplay = string.IsNullOrEmpty(newVal) ? "-" : newVal;
666→
667→                string logLine;
668→                if (day == 0)
669→                {
670→                    // 항목 추가/삭제 로그
671→                    logLine = $"[{timestamp}] 항목 {itemNo} ({itemName}) | {newDisplay}";
672→                }
673→                else
674→                {
675→                    logLine = $"[{timestamp}] 항목 {itemNo} ({itemName}) | {day}일 | {oldDisplay} → {newDisplay}";
676→                }
677→
678→                File.AppendAllText(logPath, logLine + Environment.NewLine, System.Text.Encoding.UTF8);
679→            }
680→            catch { }
681→        }
682→
683→        #endregion
684→
685→        #region PDF 출력
686→
687→        private void BtnPdf_Click(object sender, EventArgs e)
688→        {
689→            using (var sfd = new SaveFileDialog())
690→            {
691→                sfd.Filter = "PDF 파일|*.pdf";
692→                sfd.FileName = $"점검체크시트_{_currentMonth:yyyy_MM}.pdf";
693→
694→                if (sfd.ShowDialog() != DialogResult.OK) return;
695→
696→                try
697→                {
698→                    using (var pd = new PrintDocument())
699→                    {
700→                        pd.PrintPage += PrintCheckSheet;
701→                        pd.DefaultPageSettings.Landscape = true;
702→                        pd.DefaultPageSettings.Margins = new Margins(30, 30, 30, 30);
703→
704→                        // Microsoft Print to PDF 확인
705→                        bool pdfPrinterFound = false;
706→                        foreach (string printer in PrinterSettings.InstalledPrinters)
707→                        {
708→                            if (printer.Contains("Microsoft Print to PDF"))
709→                            {
710→                                pd.PrinterSettings.PrinterName = printer;
711→                                pdfPrinterFound = true;
712→                                break;
713→                            }
714→                        }
715→
716→                        if (!pdfPrinterFound)
717→                        {
718→                            MessageBox.Show("'Microsoft Print to PDF' 프린터를 찾을 수 없습니다.\n인쇄 대화상자에서 PDF 프린터를 선택해주세요.",
719→                                "알림", MessageBoxButtons.OK, MessageBoxIcon.Warning);
720→
721→                            using (var printDlg = new PrintDialog())
722→                            {
723→                                printDlg.Document = pd;
724→                                if (printDlg.ShowDialog() != DialogResult.OK) return;
725→                            }
726→                            pd.Print();
727→                        }
728→                        else
729→                        {
730→                            pd.PrinterSettings.PrintToFile = true;
731→                            pd.PrinterSettings.PrintFileName = sfd.FileName;
732→                            pd.Print();
733→                        }
734→                    }
735→
736→                    // PDF 생성 후 열기
737→                    if (File.Exists(sfd.FileName))
738→                    {
739→                        System.Diagnostics.Process.Start(sfd.FileName);
740→                        LogCheckAction(0, "PDF 출력", 0, "", sfd.FileName);
741→                    }
742→                }
743→                catch (Exception ex)
744→                {
745→                    MessageBox.Show($"PDF 생성 실패: {ex.Message}", "오류",
746→                        MessageBoxButtons.OK, MessageBoxIcon.Error);
747→                }
748→            }
749→        }
