751→        /// <summary>
752→        /// 체크시트 인쇄 렌더링 (Landscape A4)
753→        /// </summary>
754→        private void PrintCheckSheet(object sender, PrintPageEventArgs e)
755→        {
756→            Graphics g = e.Graphics;
757→            var area = e.MarginBounds;
758→            float x = area.Left;
759→            float y = area.Top;
760→            float pageW = area.Width;
761→
762→            int rowCount = dgv.Rows.Count;
763→
764→            // 폰트
765→            var fontTitle = new Font("맑은 고딕", 14, FontStyle.Bold);
766→            var fontHeader = new Font("맑은 고딕", 7);
767→            var fontHeaderBold = new Font("맑은 고딕", 7, FontStyle.Bold);
768→            var fontCell = new Font("맑은 고딕", 6.5f);
769→            var fontCellBold = new Font("맑은 고딕", 7, FontStyle.Bold);
770→
771→            var penBlack = new Pen(Color.Black, 0.5f);
772→            var penBold = new Pen(Color.Black, 1.2f);
773→            var brushBlack = Brushes.Black;
774→            var brushGreen = new SolidBrush(Color.FromArgb(0, 128, 0));
775→            var brushRed = new SolidBrush(Color.FromArgb(200, 0, 0));
776→            var sfCenter = new StringFormat { Alignment = StringAlignment.Center, LineAlignment = StringAlignment.Center };
777→            var sfLeft = new StringFormat { Alignment = StringAlignment.Near, LineAlignment = StringAlignment.Center };
778→
779→            // === 제목 ===
780→            g.DrawString("(설비/용접조건) 점검 체크시트", fontTitle, brushBlack, x + pageW / 2, y, sfCenter);
781→            y += 28;
782→
783→            // === 헤더 정보 ===
784→            string headerLine1 = $"관리부서: {txtDept.Text}    관리감독: {txtSupervisor.Text}    설비명칭: {txtEquipName.Text}    " +
785→                                 $"점검방법: 점검 항목/점검 기준/점검 방법에 따름";
786→            string headerLine2 = $"품질: {txtQuality.Text}    설비번호: {txtEquipNo.Text}    " +
787→                                 $"작성: {txtWriter.Text}    검토: {txtReviewer.Text}    승인: {txtApprover.Text}    " +
788→                                 $"{_currentMonth:yyyy년 MM월} 일상 점검";
789→            g.DrawString(headerLine1, fontHeader, brushBlack, x, y);
790→            y += 14;
791→            g.DrawString(headerLine2, fontHeader, brushBlack, x, y);
792→            y += 18;
793→
794→            // === 테이블 ===
795→            int daysInMonth = DateTime.DaysInMonth(_currentMonth.Year, _currentMonth.Month);
796→
797→            // 컬럼 폭 계산
798→            float[] colWidths = new float[5 + 31];
799→            colWidths[0] = 22;   // NO
800→            colWidths[1] = 130;  // 점검항목
801→            colWidths[2] = 125;  // 점검기준
802→            colWidths[3] = 45;   // 점검방법
803→            colWidths[4] = 48;   // 구분
804→            float fixedW = colWidths[0] + colWidths[1] + colWidths[2] + colWidths[3] + colWidths[4];
805→            float dayColW = (pageW - fixedW) / daysInMonth;
806→            for (int d = 0; d < daysInMonth; d++)
807→                colWidths[5 + d] = dayColW;
808→
809→            // 행 높이 동적 (항목 많으면 줄임)
810→            float availableH = area.Bottom - y - 30; // 서명란 여유
811→            float headerH = 18;
812→            float rowH = Math.Min(22, (availableH - headerH) / rowCount);
813→            if (rowH < 12) rowH = 12;
814→
815→            // 헤더행
816→            float cx = x;
817→            string[] headers = { "NO", "점검 항목", "점검 기준", "점검 방법", "구분" };
818→            for (int c = 0; c < 5; c++)
819→            {
820→                g.DrawRectangle(penBold, cx, y, colWidths[c], headerH);
821→                g.DrawString(headers[c], fontHeaderBold, brushBlack,
822→                    new RectangleF(cx, y, colWidths[c], headerH), sfCenter);
823→                cx += colWidths[c];
824→            }
825→            for (int d = 1; d <= daysInMonth; d++)
826→            {
827→                g.DrawRectangle(penBlack, cx, y, colWidths[4 + d], headerH);
828→                g.DrawString(d.ToString(), fontHeaderBold, brushBlack,
829→                    new RectangleF(cx, y, colWidths[4 + d], headerH), sfCenter);
830→                cx += colWidths[4 + d];
831→            }
832→            y += headerH;
833→
834→            // 데이터행 (그리드에서 직접 읽기)
835→            for (int r = 0; r < rowCount; r++)
836→            {
837→                cx = x;
838→                var row = dgv.Rows[r];
839→
840→                // 고정 컬럼 5개: NO, 항목, 기준, 방법, 구분
841→                string[] cellNames = { "colNo", "colItem", "colStandard", "colMethod", "colType" };
842→                for (int c = 0; c < 5; c++)
843→                {
844→                    g.DrawRectangle(penBlack, cx, y, colWidths[c], rowH);
845→                    string text = row.Cells[cellNames[c]].Value?.ToString() ?? "";
846→                    var fmt = (c == 0) ? sfCenter : sfLeft;
847→                    var f = (c <= 1) ? fontCellBold : fontCell;
848→                    g.DrawString(text, f, brushBlack,
849→                        new RectangleF(cx + 2, y, colWidths[c] - 4, rowH), fmt);
850→                    cx += colWidths[c];
851→                }
852→
853→                // 일자 컬럼
854→                for (int d = 1; d <= daysInMonth; d++)
855→                {
856→                    g.DrawRectangle(penBlack, cx, y, colWidths[4 + d], rowH);
857→                    string val = row.Cells[$"colDay{d}"].Value?.ToString()?.Trim() ?? "";
858→                    if (!string.IsNullOrEmpty(val))
859→                    {
860→                        var brush = val == "O" ? brushGreen : (val == "X" ? brushRed : brushBlack);
861→                        g.DrawString(val, fontCellBold, brush,
862→                            new RectangleF(cx, y, colWidths[4 + d], rowH), sfCenter);
863→                    }
864→                    cx += colWidths[4 + d];
865→                }
866→                y += rowH;
867→            }
868→
869→            // === 서명란 ===
870→            y += 10;
871→            g.DrawString($"생산 관리자 (SIGN): {txtProdSign.Text}", fontHeader, brushBlack, x, y);
872→            g.DrawString($"품질 관리자 (SIGN): {txtQualSign.Text}", fontHeader, brushBlack, x + 250, y);
873→
874→            // 폰트 해제
875→            fontTitle.Dispose();
876→            fontHeader.Dispose();
877→            fontHeaderBold.Dispose();
878→            fontCell.Dispose();
879→            fontCellBold.Dispose();
880→            penBlack.Dispose();
881→            penBold.Dispose();
882→            brushGreen.Dispose();
883→            brushRed.Dispose();
884→
885→            e.HasMorePages = false;
886→        }
887→
888→        #endregion
889→    }
890→}
