        /// <summary>
        /// 선택된 항목의 참조사진 로드
        /// </summary>
        private void LoadPhoto(int itemIndex)
        {
            // 파일명: 01.jpg, 01.png 등
            string prefix = (itemIndex + 1).ToString("D2");
            string itemName = "";
            if (itemIndex < dgv.Rows.Count)
                itemName = dgv.Rows[itemIndex].Cells["colItem"].Value?.ToString() ?? "";
            lblPhotoTitle.Text = $"{itemIndex + 1}. {itemName}";

            // 확장자 순회
            string[] exts = { ".jpg", ".jpeg", ".png", ".bmp", ".gif" };
            foreach (var ext in exts)
            {
                string path = Path.Combine(_photoPath, prefix + ext);
                if (File.Exists(path))
                {
                    try
                    {
                        // 파일 잠금 방지
                        using (var fs = new FileStream(path, FileMode.Open, FileAccess.Read))
                        {
                            pictureBox.Image?.Dispose();
                            pictureBox.Image = Image.FromStream(fs);
                        }
                        return;
                    }
                    catch { }
                }
            }

            // 사진 없음
            pictureBox.Image?.Dispose();
            pictureBox.Image = null;
        }

